def make_front_matter_page_numbering_docx(
    path: Path,
    *,
    existing_frontmatter_section: bool = False,
    missing_abstract: bool = False,
    missing_body_start: bool = False,
    inline_abstract: bool = False,
) -> Path:
    abstract_title = "\u524d\u8a00" if missing_abstract else "\u6458 \u8981"
    if inline_abstract and not missing_abstract:
        abstract_title = "\u6458 \u8981\uff1a\u4e2d\u6587\u6458\u8981\u5185\u5bb9\u3002"
    body_heading = "" if missing_body_start else '<w:p><w:pPr><w:pageBreakBefore/></w:pPr><w:r><w:t>1 \u5f15\u8a00</w:t></w:r></w:p>'
    section_paragraph = ""
    if existing_frontmatter_section:
        section_paragraph = (
            '<w:p><w:pPr><w:sectPr><w:pgNumType w:fmt="decimal" w:start="3"/></w:sectPr></w:pPr>'
            '<w:r><w:t>\u76ee\u5f55</w:t></w:r></w:p>'
        )
    else:
        section_paragraph = '<w:p><w:r><w:t>\u76ee\u5f55</w:t></w:r></w:p>'
    return make_raw_docx(
        path,
        f'''
    <w:p><w:r><w:t>{escape(abstract_title)}</w:t></w:r></w:p>
    <w:p><w:r><w:t>\u4e2d\u6587\u6458\u8981\u5185\u5bb9\u3002</w:t></w:r></w:p>
    <w:p><w:r><w:t>ABSTRACT</w:t></w:r></w:p>
    <w:p><w:r><w:t>English abstract.</w:t></w:r></w:p>
    {section_paragraph}
    {body_heading}
''',
        body_sect_pr=(
            '<w:sectPr><w:pgNumType w:fmt="decimal" w:start="4"/>'
            '<w:pgSz w:w="11906" w:h="16838"/>'
            '<w:pgMar w:top="1701" w:right="1588" w:bottom="1418" w:left="1701" w:header="0" w:footer="1134" w:gutter="0"/>'
            '<w:cols w:num="1" w:space="720"/>'
            '<w:docGrid w:type="lines" w:linePitch="312" w:charSpace="0"/>'
            '</w:sectPr>'
        ),
    )


def xml_text_node(text: str) -> str:
    preserve = ' xml:space="preserve"' if text.startswith(" ") or text.endswith(" ") else ""
    return f"<w:t{preserve}>{escape(text)}</w:t>"


def abstract_surface_body_xml(*, zh_prefix: bool = True, en_content_font: str = "", blank_token: str = "\u25a1\u25a1") -> str:
    zh_prefix_run = (
        f'<w:r><w:rPr><w:rFonts w:ascii="SimSun" w:hAnsi="SimSun"/>'
        f'<w:sz w:val="24"/></w:rPr>{xml_text_node(blank_token)}</w:r>'
        if zh_prefix
        else ""
    )
    en_font_xml = f'<w:rFonts w:ascii="{escape(en_content_font)}" w:hAnsi="{escape(en_content_font)}"/>' if en_content_font else ""
    en_prefix_run = (
        f'<w:r><w:rPr><w:rFonts w:ascii="SimSun" w:hAnsi="SimSun"/>'
        f'<w:sz w:val="24"/></w:rPr>{xml_text_node(blank_token)}</w:r>'
    )
    return f'''
    <w:p><w:r><w:t>\u6458 \u8981{escape(blank_token)}</w:t></w:r></w:p>
    <w:p>{zh_prefix_run}<w:r><w:rPr><w:sz w:val="24"/></w:rPr><w:t>\u4e2d\u6587\u6458\u8981\u6b63\u6587\u3002</w:t></w:r></w:p>
    <w:p><w:r><w:t>\u5173\u952e\u8bcd:</w:t></w:r><w:r><w:t>\u65c5\u6e38; \u8bc4\u8bba; \u60c5\u611f</w:t></w:r></w:p>
    <w:p><w:r><w:t>Abstract</w:t></w:r></w:p>
    <w:p>{en_prefix_run}<w:r><w:rPr>{en_font_xml}<w:sz w:val="24"/></w:rPr><w:t>English abstract body text.</w:t></w:r></w:p>
    <w:p><w:r><w:t>Key words:</w:t></w:r><w:r><w:t>tourism; sentiment</w:t></w:r></w:p>
    <w:p><w:r><w:t>1 Introduction</w:t></w:r></w:p>
'''


