def make_protected_surface_evidence_set(
    base_path: Path,
    *,
    task_mode: str,
    reviewed_output: Path,
    rendered_pdf: Path,
    page_images: list[Path],
) -> dict[str, str]:
    evidence_paths: dict[str, str] = {}
    baseline_sha = file_sha256(reviewed_output) if reviewed_output.exists() else "0" * 64
    rendered_region = str(page_images[0] if page_images else rendered_pdf)
    for surface_id, surface_label in PROTECTED_FRONT_MATTER_SURFACE_LABELS.items():
        evidence_path = base_path.with_name(f"{base_path.stem}.{surface_id}{base_path.suffix}")
        whole_pagination_kwargs = {}
        if surface_id == "whole_document_pagination":
            surface_label = surface_id
            whole_pagination_kwargs = {
                "toc_title_confirmed": "yes",
                "toc_level_formatting_confirmed": "yes",
                "toc_dotted_leader_confirmed": "yes",
                "toc_page_number_column_confirmed": "yes",
                "toc_restored_confirmed": "yes",
                "toc_page_occupancy_confirmed": "yes",
            }
        if surface_id in {
            "references_title",
            "references_entries",
            "acknowledgement_title",
            "acknowledgement_body",
            "appendix_title",
            "appendix_body",
        }:
            whole_pagination_kwargs.update(
                {
                    "tail_block_title_baseline_confirmed": "yes",
                    "tail_block_opener_fresh_page_confirmed": "yes",
                    "tail_block_separation_confirmed": "yes",
                    "tail_block_singular_owner_confirmed": "yes",
                    "references_title_indentation_confirmed": "yes",
                    "references_entries_indentation_confirmed": "yes",
                    "acknowledgement_title_indentation_confirmed": "yes",
                    "acknowledgement_body_indentation_confirmed": "yes",
                    "end_matter_rendered_geometry_confirmed": "yes",
                }
            )
        make_review_evidence(
            evidence_path,
            evidence_type="thesis-rendered-page",
            task_mode=task_mode,
            reviewed_output=reviewed_output,
            artifact_paths=[rendered_pdf, *page_images],
            target_surface=surface_label,
            target_identifier=surface_id,
            target_region=f"{surface_label} rendered region",
            blast_radius=f"{surface_label} and adjacent front-matter surfaces",
            neighbors=f"adjacent surface family for {surface_id}",
            checks=f"{surface_id} paragraph/run metrics, rendered region, and template baseline comparison",
            summary=f"{surface_id} protected surface evidence passed",
            baseline_source_path_and_sha256=f"{reviewed_output} sha256={baseline_sha}",
            baseline_surface_id=surface_id,
            baseline_paragraph_run_path=f"{reviewed_output}::{surface_id}::baseline paragraph/run",
            baseline_metrics=f"{surface_id} baseline font, spacing, alignment, indentation, tab, and run properties",
            actual_paragraph_run_path=f"{reviewed_output}::{surface_id}::actual paragraph/run",
            actual_metrics=f"{surface_id} actual font, spacing, alignment, indentation, tab, and run properties",
            rendered_region_image_path=rendered_region,
            **whole_pagination_kwargs,
        )
        evidence_paths[surface_id] = str(evidence_path)
    return evidence_paths


def surface_evidence_path(evidence_paths: str | dict[str, str], surface_id: str) -> str:
    if isinstance(evidence_paths, dict):
        return evidence_paths.get(surface_id, evidence_paths.get("_default", "none"))
    return evidence_paths


