def run_validator(record_path: Path) -> subprocess.CompletedProcess[str]:
    proc = subprocess.run(
        [str(PYTHON_EXE), str(VALIDATOR), "--skill-root", str(SKILL_ROOT), "--gate-record", str(record_path)],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(VALIDATOR_TIMEOUT),
    )
    if proc.stderr:
        proc.stdout = (proc.stdout or "") + proc.stderr
    return proc


def run_validator_for_skill_root(skill_root: Path) -> subprocess.CompletedProcess[str]:
    return subprocess.run(
        [str(PYTHON_EXE), str(skill_root / "scripts" / "validate_skill_gate.py"), "--skill-root", str(skill_root)],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(VALIDATOR_TIMEOUT),
    )


def list_renderer_process_ids() -> set[int]:
    proc = subprocess.run(
        [
            "powershell",
            "-NoProfile",
            "-Command",
            "Get-Process WINWORD,wps,soffice -ErrorAction SilentlyContinue | Select-Object -ExpandProperty Id",
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )
    ids: set[int] = set()
    for line in (proc.stdout or "").splitlines():
        line = line.strip()
        if not line:
            continue
        try:
            ids.add(int(line))
        except ValueError:
            continue
    return ids


def cleanup_new_renderer_processes(existing_ids: set[int]) -> None:
    for _ in range(3):
        current_ids = list_renderer_process_ids()
        new_ids = sorted(current_ids - existing_ids)
        if not new_ids:
            return
        subprocess.run(
            [
                "powershell",
                "-NoProfile",
                "-Command",
                f"Stop-Process -Id {','.join(str(pid) for pid in new_ids)} -Force -ErrorAction SilentlyContinue",
            ],
            capture_output=True,
            text=True,
            encoding="utf-8",
            errors="replace",
            timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
        )
        time.sleep(1.0)


TRANSIENT_INTEGRATION_FAILURE_TOKENS = (
    "rpc server is unavailable",
    "call was rejected by callee",
    "comexception",
    "rpc server unavailable",
    "call rejected",
)


def integration_failure_is_transient(output: str) -> bool:
    lowered = output.lower()
    return any(token in lowered for token in TRANSIENT_INTEGRATION_FAILURE_TOKENS)


def run_integration_case(case_name: str, temp_root: Path) -> subprocess.CompletedProcess[str]:
    attempt_roots = [temp_root, temp_root.with_name(f"{temp_root.name}_retry1")]
    last_proc: subprocess.CompletedProcess[str] | None = None
    for attempt_index, attempt_root in enumerate(attempt_roots):
        existing_renderer_ids = list_renderer_process_ids()
        try:
            try:
                report_path = attempt_root / "integration-report.md"
                proc = subprocess.run(
                    [
                        str(PYTHON_EXE),
                        str(INTEGRATION_GATE),
                        "--case",
                        case_name,
                        "--temp-root",
                        str(attempt_root),
                        "--quiet",
                        "--report-out",
                        str(report_path),
                    ],
                    capture_output=True,
                    text=True,
                    encoding="utf-8",
                    errors="replace",
                    timeout=timeout_seconds(INTEGRATION_CASE_TIMEOUT),
                )
            except subprocess.TimeoutExpired as exc:
                proc = subprocess.CompletedProcess(
                    exc.cmd,
                    124,
                    exc.stdout or "",
                    f"integration case timed out after {INTEGRATION_CASE_TIMEOUT}s: {exc}",
                )
        finally:
            cleanup_new_renderer_processes(existing_renderer_ids)
        last_proc = proc
        combined = (proc.stdout or "") + (proc.stderr or "")
        if proc.returncode == 0:
            return proc
        if attempt_index + 1 >= len(attempt_roots) or not integration_failure_is_transient(combined):
            return proc
        time.sleep(1.5)
    assert last_proc is not None
    return last_proc


def make_picture_docx(path: Path, image_path: Path, *, caption: str) -> str:
    path.parent.mkdir(parents=True, exist_ok=True)
    create = subprocess.run(
        ["officecli", "create", str(path)],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=True,
        timeout=timeout_seconds(120),
    )
    subprocess.run(
        ["officecli", "add", str(path), "/body", "--type", "paragraph", "--prop", "text=picture holder anchor"],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=True,
        timeout=timeout_seconds(120),
    )
    pic = subprocess.run(
        ["officecli", "add", str(path), "/body/p[1]", "--type", "picture", "--prop", f"path={image_path}", "--prop", "width=6cm"],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=True,
        timeout=timeout_seconds(120),
    )
    subprocess.run(
        ["officecli", "add", str(path), "/body", "--type", "paragraph", "--prop", f"text={caption}"],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=True,
        timeout=timeout_seconds(120),
    )
    subprocess.run(
        ["officecli", "close", str(path)],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=False,
        timeout=timeout_seconds(120),
    )
    match = re.search(r"/body/p\[@paraId=([0-9A-F]+)\]", pic.stdout)
    if match:
        return match.group(1)
    with zipfile.ZipFile(path) as zf:
        document_xml = zf.read("word/document.xml").decode("utf-8", errors="replace")
    fallback = re.search(r'w14:paraId="([0-9A-F]+)"[^>]*>.*?<w:drawing>', document_xml)
    if fallback:
        return fallback.group(1)
    raise AssertionError(f"picture paragraph paraId not found in officecli output or document XML: {pic.stdout}")


def make_toc_picture_docx(path: Path, image_path: Path) -> Path:
    from docx import Document  # type: ignore
    from docx.shared import Inches  # type: ignore

    path.parent.mkdir(parents=True, exist_ok=True)
    doc = Document()
    doc.add_paragraph("Contents")
    doc.add_picture(str(image_path), width=Inches(1.0))
    doc.add_paragraph("1 Introduction")
    doc.add_paragraph("1 Introduction")
    doc.save(path)
    return path


def make_toc_table_picture_docx(path: Path, image_path: Path) -> Path:
    from docx import Document  # type: ignore
    from docx.shared import Inches  # type: ignore

    path.parent.mkdir(parents=True, exist_ok=True)
    doc = Document()
    doc.add_paragraph("Contents")
    table = doc.add_table(rows=1, cols=1)
    table.cell(0, 0).paragraphs[0].add_run().add_picture(str(image_path), width=Inches(1.0))
    doc.add_paragraph("1 Introduction")
    doc.add_paragraph("1 Introduction")
    doc.save(path)
    return path


