def copy_docx_replacing_media(source_docx: Path, final_docx: Path, replacement_png: Path, *, remove_media: bool = False) -> Path:
    final_docx.parent.mkdir(parents=True, exist_ok=True)
    tmp_docx = final_docx.with_suffix(".tmp.docx")
    with zipfile.ZipFile(source_docx, "r") as zin, zipfile.ZipFile(tmp_docx, "w", zipfile.ZIP_DEFLATED) as zout:
        media_name = next(
            name
            for name in zin.namelist()
            if name.startswith("word/media/") and Path(name).suffix.lower() in {".png", ".jpg", ".jpeg"}
        )
        rels_name = "word/_rels/document.xml.rels"
        for item in zin.infolist():
            if remove_media and item.filename == media_name:
                continue
            payload = zin.read(item.filename)
            if item.filename == media_name:
                payload = replacement_png.read_bytes()
            elif remove_media and item.filename == rels_name:
                payload = re.sub(
                    rb'\s*<Relationship[^>]+Type="[^"]*/image"[^>]*/>',
                    b"",
                    payload,
                )
            zout.writestr(item, payload)
    shutil.move(str(tmp_docx), str(final_docx))
    return final_docx


def copy_docx_broken_first_media_target(source_docx: Path, final_docx: Path) -> Path:
    from xml.etree import ElementTree as ET

    final_docx.parent.mkdir(parents=True, exist_ok=True)
    tmp_docx = final_docx.with_suffix(".tmp.docx")
    rel_ns = "http://schemas.openxmlformats.org/package/2006/relationships"
    with zipfile.ZipFile(source_docx, "r") as zin, zipfile.ZipFile(tmp_docx, "w", zipfile.ZIP_DEFLATED) as zout:
        rel_root = ET.fromstring(zin.read("word/_rels/document.xml.rels"))
        for rel in rel_root.findall(f"{{{rel_ns}}}Relationship"):
            if rel.attrib.get("Type", "").endswith("/image"):
                rel.attrib["Target"] = "media/missing-target.png"
                break
        for item in zin.infolist():
            if item.filename == "word/_rels/document.xml.rels":
                zout.writestr(item, ET.tostring(rel_root, encoding="utf-8", xml_declaration=True))
            else:
                zout.writestr(item, zin.read(item.filename))
    shutil.move(str(tmp_docx), str(final_docx))
    return final_docx


def copy_docx_mutating_first_drawing_extent(source_docx: Path, final_docx: Path) -> Path:
    from xml.etree import ElementTree as ET

    final_docx.parent.mkdir(parents=True, exist_ok=True)
    tmp_docx = final_docx.with_suffix(".tmp.docx")
    wp_ns = "http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing"
    with zipfile.ZipFile(source_docx, "r") as zin, zipfile.ZipFile(tmp_docx, "w", zipfile.ZIP_DEFLATED) as zout:
        document_root = ET.fromstring(zin.read("word/document.xml"))
        extent = document_root.find(f".//{{{wp_ns}}}extent")
        if extent is None:
            raise AssertionError("fixture DOCX has no wp:extent")
        original_cx = int(extent.attrib.get("cx", "0") or "0")
        extent.attrib["cx"] = str(original_cx + 12345)
        for item in zin.infolist():
            if item.filename == "word/document.xml":
                zout.writestr(item, ET.tostring(document_root, encoding="utf-8", xml_declaration=True))
            else:
                zout.writestr(item, zin.read(item.filename))
    shutil.move(str(tmp_docx), str(final_docx))
    return final_docx


def copy_docx_mutating_first_drawing_caption_adjacency(source_docx: Path, final_docx: Path) -> Path:
    from xml.etree import ElementTree as ET

    final_docx.parent.mkdir(parents=True, exist_ok=True)
    tmp_docx = final_docx.with_suffix(".tmp.docx")
    w_ns = "http://schemas.openxmlformats.org/wordprocessingml/2006/main"
    with zipfile.ZipFile(source_docx, "r") as zin, zipfile.ZipFile(tmp_docx, "w", zipfile.ZIP_DEFLATED) as zout:
        document_root = ET.fromstring(zin.read("word/document.xml"))
        paragraphs = document_root.findall(f".//{{{w_ns}}}body/{{{w_ns}}}p")
        for index, paragraph in enumerate(paragraphs[:-1]):
            if paragraph.find(f".//{{{w_ns}}}drawing") is None:
                continue
            text_node = ET.Element(f"{{{w_ns}}}p")
            run = ET.SubElement(text_node, f"{{{w_ns}}}r")
            text = ET.SubElement(run, f"{{{w_ns}}}t")
            text.text = "Inserted body text between image and caption"
            body = document_root.find(f".//{{{w_ns}}}body")
            if body is None:
                raise AssertionError("fixture DOCX has no body")
            body_children = list(body)
            child_index = body_children.index(paragraph)
            body.insert(child_index + 1, text_node)
            break
        else:
            raise AssertionError("fixture DOCX has no drawing paragraph")
        for item in zin.infolist():
            if item.filename == "word/document.xml":
                zout.writestr(item, ET.tostring(document_root, encoding="utf-8", xml_declaration=True))
            else:
                zout.writestr(item, zin.read(item.filename))
    shutil.move(str(tmp_docx), str(final_docx))
    return final_docx


def copy_docx_rewriting_paragraph_before_first_drawing(source_docx: Path, final_docx: Path) -> Path:
    from xml.etree import ElementTree as ET

    final_docx.parent.mkdir(parents=True, exist_ok=True)
    tmp_docx = final_docx.with_suffix(".tmp.docx")
    w_ns = "http://schemas.openxmlformats.org/wordprocessingml/2006/main"
    with zipfile.ZipFile(source_docx, "r") as zin, zipfile.ZipFile(tmp_docx, "w", zipfile.ZIP_DEFLATED) as zout:
        document_root = ET.fromstring(zin.read("word/document.xml"))
        paragraphs = document_root.findall(f".//{{{w_ns}}}body/{{{w_ns}}}p")
        for index, paragraph in enumerate(paragraphs):
            if paragraph.find(f".//{{{w_ns}}}drawing") is None or index == 0:
                continue
            previous = paragraphs[index - 1]
            text_node = previous.find(f".//{{{w_ns}}}t")
            if text_node is None:
                run = previous.find(f".//{{{w_ns}}}r")
                if run is None:
                    run = ET.SubElement(previous, f"{{{w_ns}}}r")
                text_node = ET.SubElement(run, f"{{{w_ns}}}t")
            text_node.text = "Rewritten prose before the image while media and caption stay unchanged"
            break
        else:
            raise AssertionError("fixture DOCX has no drawing paragraph with previous prose")
        for item in zin.infolist():
            if item.filename == "word/document.xml":
                zout.writestr(item, ET.tostring(document_root, encoding="utf-8", xml_declaration=True))
            else:
                zout.writestr(item, zin.read(item.filename))
    shutil.move(str(tmp_docx), str(final_docx))
    return final_docx


def copy_docx_inserting_leading_paragraph(source_docx: Path, final_docx: Path) -> Path:
    from xml.etree import ElementTree as ET

    final_docx.parent.mkdir(parents=True, exist_ok=True)
    tmp_docx = final_docx.with_suffix(".tmp.docx")
    w_ns = "http://schemas.openxmlformats.org/wordprocessingml/2006/main"
    with zipfile.ZipFile(source_docx, "r") as zin, zipfile.ZipFile(tmp_docx, "w", zipfile.ZIP_DEFLATED) as zout:
        document_root = ET.fromstring(zin.read("word/document.xml"))
        body = document_root.find(f".//{{{w_ns}}}body")
        if body is None:
            raise AssertionError("fixture DOCX has no body")
        text_node = ET.Element(f"{{{w_ns}}}p")
        run = ET.SubElement(text_node, f"{{{w_ns}}}r")
        text = ET.SubElement(run, f"{{{w_ns}}}t")
        text.text = "Inserted leading paragraph that shifts drawing indexes only"
        body.insert(0, text_node)
        for item in zin.infolist():
            if item.filename == "word/document.xml":
                zout.writestr(item, ET.tostring(document_root, encoding="utf-8", xml_declaration=True))
            else:
                zout.writestr(item, zin.read(item.filename))
    shutil.move(str(tmp_docx), str(final_docx))
    return final_docx


def first_docx_media_info(docx_path: Path, *, part: str = "word/document.xml") -> dict[str, str]:
    from thesis_figure_contract import docx_image_relationship_manifest

    media = docx_image_relationship_manifest(docx_path)
    for info in media.values():
        if info.get("source_part") == part:
            return info
    return next(iter(media.values()))


def add_docx_binding_fields(manifest: dict[str, object], *, source_docx: Path, final_docx: Path) -> dict[str, object]:
    manifest["source_docx_path"] = str(source_docx)
    manifest["source_docx_sha256"] = file_sha256(source_docx)
    manifest["final_docx_path"] = str(final_docx)
    manifest["final_docx_sha256"] = file_sha256(final_docx)
    return manifest


def add_manifest_media_binding(
    manifest: dict[str, object],
    *,
    source_docx: Path,
    final_docx: Path,
    mutation_intent: str = "replace_existing",
) -> dict[str, object]:
    source_info = first_docx_media_info(source_docx)
    final_info = first_docx_media_info(final_docx)
    figures = manifest.get("figures")
    if not isinstance(figures, dict) or not figures:
        return manifest
    entry = next(entry for entry in figures.values() if isinstance(entry, dict))
    entry.update(
        {
            "mutation_intent": mutation_intent,
            "explicit_replacement_authorization_source": "selftest approved replacement",
            "explicit_replacement_authorization_scope": "single body figure",
            "original_rid": source_info["rid"],
            "original_media_target": source_info["target"],
            "original_media_sha256": source_info["sha256"],
            "final_rid": final_info["rid"],
            "final_media_target": final_info["target"],
            "final_media_sha256": final_info["sha256"],
            "target_anchor_caption": str(entry.get("caption") or "Figure 4-1 Runtime screenshot"),
            "target_anchor_not_protected_surface_verdict": "pass",
        }
    )
    return manifest


def bind_manifest_to_source_copy(
    manifest: dict[str, object],
    *,
    td: Path,
    final_docx: Path,
    stem: str,
) -> tuple[dict[str, object], Path]:
    source_docx = td / f"{stem}.source.docx"
    shutil.copyfile(final_docx, source_docx)
    return add_docx_binding_fields(manifest, source_docx=source_docx, final_docx=final_docx), source_docx


def make_header_picture_docx(path: Path, image_path: Path, *, width_inches: float = 0.5) -> Path:
    from docx import Document  # type: ignore
    from docx.shared import Inches  # type: ignore

    path.parent.mkdir(parents=True, exist_ok=True)
    doc = Document()
    header = doc.sections[0].header
    header.paragraphs[0].add_run().add_picture(str(image_path), width=Inches(width_inches))
    doc.add_paragraph("1 Introduction")
    doc.add_paragraph("Body text.")
    doc.save(path)
    return path


