def make_wps_named_size_evidence(
    path: Path,
    *,
    docx_path: str | Path,
    entry_count: int = 1,
    expected_size_name: str = "\u4e94\u53f7",
    expected_size_half_points: str = "21",
    verdict: str = "pass",
) -> Path:
    docx = Path(docx_path)
    payload = {
        "schema": "graduation-project-builder.wps-reference-entry-ui-font.v1",
        "docxPath": str(docx),
        "docxSha256": file_sha256(docx) if docx.exists() else "0" * 64,
        "expectedWpsDisplaySizeName": expected_size_name,
        "expectedSizeHalfPoints": expected_size_half_points,
        "checkedEntryCount": entry_count,
        "verdict": verdict,
        "entries": [
            {
                "entryIndex": index,
                "rangeStart": index * 10,
                "rangeEnd": index * 10 + 9,
                "selectedText": f"[{index}] reference",
                "fontNameAscii": "Times New Roman",
                "fontNameFarEast": "宋体",
                "fontSizePoints": 10.5,
                "inferredWpsDisplaySizeName": expected_size_name,
                "verdict": verdict,
            }
            for index in range(1, entry_count + 1)
        ],
    }
    write_text(path, json.dumps(payload, ensure_ascii=False, indent=2) + "\n")
    return path


def make_docx_font_audit_report(
    path: Path,
    *,
    passed: bool = True,
    docx_path: str | Path | None = None,
    size_policy_source: str = "template-derived",
    expected_size_name: str = "template-derived",
    expected_size_half_points: str = "template-derived",
    wps_evidence_path: str | Path | None = None,
    wps_evidence_verdict: str = "not-required",
    entry_count: int = 1,
    checked_run_count: int = 1,
    content_format_model_checks: str | None = None,
    content_format_model_source: str | Path | None = None,
) -> None:
    result = "pass" if passed else "fail"
    target_docx = docx_path if docx_path is not None else path.with_suffix(".docx")
    target_docx_path = Path(target_docx)
    target_sha = file_sha256(target_docx_path) if target_docx_path.exists() else "0" * 64
    reference_sha = target_sha if target_docx_path.exists() else "0" * 64
    wps_path_value = str(wps_evidence_path) if wps_evidence_path is not None else "not-required"
