def make_docx_body_style_audit_report(
    path: Path,
    *,
    passed: bool = True,
    reference_docx_path: str | Path | None = None,
    final_docx_path: str | Path | None = None,
    binding_summary: str | None = None,
    normal_baseline_summary: str | None = None,
    body_family_summary: str | None = None,
    direct_visible_summary: str | None = None,
) -> None:
    if binding_summary is None:
        binding_summary = (
            "passed 8/8 body paragraphs explicitly bind to `Normal`"
            if passed
            else "failed 3/8 body paragraphs missing explicit binding to `Normal`"
        )
    if normal_baseline_summary is None:
        normal_baseline_summary = (
            "passed baseline preserved on `Normal`"
            if passed
            else "failed baseline drift on `Normal`"
        )
    if body_family_summary is None:
        body_family_summary = (
            "passed one explicit body family preserved across 8 body paragraphs"
            if passed
            else "failed fragmented body family: fallback_only=3, explicit_families=2"
        )
    heading_contamination_summary = (
        "passed no body prose paragraph uses heading-style or outline-level formatting"
        if passed
        else "failed 1 body prose paragraphs use heading-style or outline-level formatting"
    )
    if direct_visible_summary is None:
        direct_visible_summary = (
            "passed strict direct visible metrics on body prose, headings, image holders, captions, style ids, and font slots"
            if passed
            else "failed strict direct visible metrics on body prose"
        )
    result = (
        "pass"
        if binding_summary.startswith("passed")
        and normal_baseline_summary.startswith("passed")
        and body_family_summary.startswith("passed")
        and heading_contamination_summary.startswith("passed")
        and direct_visible_summary.startswith("passed strict")
        else "fail"
    )
    reference_docx = reference_docx_path if reference_docx_path is not None else path.with_suffix(".reference.docx")
    final_docx = final_docx_path if final_docx_path is not None else path.with_suffix(".docx")
    reference_sha = file_sha256(Path(reference_docx)) if Path(reference_docx).exists() else "0" * 64
    final_sha = file_sha256(Path(final_docx)) if Path(final_docx).exists() else "0" * 64
    write_text(
        path,
        textwrap.dedent(
            f"""
            # DOCX Body Style Audit

            - reference docx path: {reference_docx}
            - reference docx sha256: {reference_sha}
            - final docx path: {final_docx}
            - final docx sha256: {final_sha}
            - body paragraphs checked: 8
            - reference inferred body style: Normal (Normal)
            - final matched body style: Normal
            - body style binding summary: {binding_summary}
            - Normal baseline preservation summary: {normal_baseline_summary}
            - body paragraph family consistency summary: {body_family_summary}
            - body heading contamination summary: {heading_contamination_summary}
            - body mixed-script font summary: {'passed mixed-script body runs preserve template font slots' if passed else 'failed mixed-script body run font drift'}
            - body direct visible metrics summary: {direct_visible_summary}
            - result: {result}

            ## Binding Issues
            - {'none' if binding_summary.startswith('passed') else 'body style binding issue at sample section'}

            ## Normal Baseline Issues
            - {'none' if normal_baseline_summary.startswith('passed') else 'alignment: expected `both` but found `left`'}

            ## Body Family Issues
            - {'none' if body_family_summary.startswith('passed') else 'body paragraph family mismatch'}

            ## Heading Contamination Issues
            - {'none' if heading_contamination_summary.startswith('passed') else 'body prose paragraph uses heading-style formatting'}

            ## Mixed-Script Body Issues
            - {'none' if passed else 'mixed-script body font drift'}

            ## Direct Visible Metric Issues
            - {'none' if direct_visible_summary.startswith('passed strict') else 'strict direct visible metric drift'}
            """
        ).strip()
        + "\n",
    )


def prepare_toc_acceptance_generator_fixture(td: Path) -> dict[str, Path | str]:
    root = td / "toc-acceptance-generator"
    root.mkdir(parents=True, exist_ok=True)
    template_docx = make_toc_metric_docx(root / "template.docx")
    final_docx = make_toc_metric_docx(root / "final.docx")
    final_pdf = make_pdf_with_text(root / "final.pdf", "Contents\n1 Introduction\n1.1 Background")
    page_dir = root / "pages"
    page_dir.mkdir(exist_ok=True)
    template_image = make_png_file(root / "template-toc.png")
    actual_image = make_png_file(root / "actual-toc.png")
    make_png_file(page_dir / "page-001.png")
    surface_geometry_json = root / "surface-geometry.json"
    surface_paragraph_typography_json = root / "surface-paragraph-typography.json"
    toc_geometry_json = root / "toc-geometry.json"
    toc_paragraph_typography_json = root / "toc-paragraph-typography.json"
    whole_pagination_json = root / "whole-pagination.json"
    write_surface_geometry_json(surface_geometry_json, template_image, actual_image)
    write_surface_paragraph_typography_json(surface_paragraph_typography_json)
    write_toc_geometry_json(
        toc_geometry_json,
        template_image,
        actual_image,
        template_docx=template_docx,
        final_docx=final_docx,
    )
    write_whole_pagination_json(whole_pagination_json, template_docx=template_docx, final_docx=final_docx)
    toc_measure = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "measure_toc_paragraph_typography.py"),
            "--template-docx",
            str(template_docx),
            "--final-docx",
            str(final_docx),
            "--output",
            str(toc_paragraph_typography_json),
            "--fail-on-drift",
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )
    citation_audit = root / "citation-audit.md"
    font_audit = root / "font-audit.md"
    body_style_audit = root / "body-style-audit.md"
    self_check = root / "self-check.md"
    template_profile = make_template_profile_stub(root / "template-profile.json", template_docx)
    make_dummy_citation_audit_report(citation_audit, passed=True, document_path=final_docx)
    make_docx_font_audit_report(font_audit, passed=True, docx_path=final_docx)
    make_docx_body_style_audit_report(
        body_style_audit,
        passed=True,
        reference_docx_path=template_docx,
        final_docx_path=final_docx,
    )
    make_sample_self_check_pass_report(self_check, document_path=final_docx)
    humanizer_evidence = make_humanizer_evidence_for_route(root / "humanizer.md", "both")
    transaction_record = make_thesis_transaction_record(root / "transaction.json", final_docx=final_docx)
    return {
        "root": root,
        "template_docx": template_docx,
        "final_docx": final_docx,
        "final_pdf": final_pdf,
        "self_check": self_check,
        "citation_audit": citation_audit,
        "font_audit": font_audit,
        "body_style_audit": body_style_audit,
        "template_profile": template_profile,
        "surface_geometry_json": surface_geometry_json,
        "surface_paragraph_typography_json": surface_paragraph_typography_json,
        "toc_geometry_json": toc_geometry_json,
        "toc_paragraph_typography_json": toc_paragraph_typography_json,
        "whole_pagination_json": whole_pagination_json,
        "humanizer_evidence": humanizer_evidence,
        "transaction_record": transaction_record,
        "toc_measure_output": (toc_measure.stdout or "") + (toc_measure.stderr or ""),
        "toc_measure_returncode": str(toc_measure.returncode),
    }


def run_acceptance_generator_for_fixture(
    fixture: dict[str, Path | str],
    output: Path,
    *,
    toc_geometry_json: Path | None = None,
    whole_pagination_json: Path | None = None,
) -> subprocess.CompletedProcess[str]:
    command = [
        str(PYTHON_EXE),
        str(SKILL_ROOT / "scripts" / "generate_thesis_acceptance_record.py"),
        "--template",
        str(fixture["template_docx"]),
        "--source-docx",
        str(fixture.get("source_docx", fixture["template_docx"])),
        "--final-docx",
        str(fixture["final_docx"]),
        "--final-pdf",
        str(fixture["final_pdf"]),
        "--self-check",
        str(fixture["self_check"]),
        "--citation-audit",
        str(fixture["citation_audit"]),
        "--font-audit",
        str(fixture["font_audit"]),
        "--body-style-audit",
        str(fixture["body_style_audit"]),
        "--template-profile",
        str(fixture["template_profile"]),
        "--surface-geometry-json",
        str(fixture["surface_geometry_json"]),
        "--surface-paragraph-typography-json",
        str(fixture["surface_paragraph_typography_json"]),
        "--toc-geometry-json",
        str(toc_geometry_json or fixture["toc_geometry_json"]),
        "--toc-paragraph-typography-json",
        str(fixture["toc_paragraph_typography_json"]),
        "--whole-pagination-json",
        str(whole_pagination_json or fixture["whole_pagination_json"]),
        "--humanizer-evidence",
        str(fixture["humanizer_evidence"]),
        "--transaction-record",
        str(fixture["transaction_record"]),
        "--validator",
        f"{PYTHON_EXE} {SKILL_ROOT / 'scripts' / 'validate_skill_gate.py'}",
        "--selftest-command",
        f"{PYTHON_EXE} {SKILL_ROOT / 'scripts' / 'selftest_skill_flow.py'}",
    ]
    asset_manifest = fixture.get("asset_manifest")
    if asset_manifest:
        command.extend(["--asset-manifest", str(asset_manifest)])
    comment_resolution_ledger = fixture.get("comment_resolution_ledger")
    if comment_resolution_ledger:
        command.extend(["--comment-resolution-ledger", str(comment_resolution_ledger)])
    command.extend(["--output", str(output)])
    return subprocess.run(
        command,
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(MEDIUM_SUBPROCESS_TIMEOUT),
    )


def build_thesis_bundle(td: Path, task_mode: str) -> tuple[Path, Path, list[Path], Path, Path, Path, Path, Path]:
    review_copy = make_dummy_file(td / "review_copy.docx")
    rendered_pdf = make_dummy_file(td / "rendered.pdf")
    page_images = [make_dummy_file(td / "pages" / "page-1.png"), make_dummy_file(td / "pages" / "page-2.png")]
    thesis_ev = td / "render.md"
    para_ev = td / "paragraph.md"
    touched_ev = td / "touched.md"
    figure_ev = td / "figure.md"
    citation_audit = td / "citation_audit.md"

    make_review_evidence(
        thesis_ev,
        evidence_type="thesis-rendered-page",
        task_mode=task_mode,
        reviewed_output=review_copy,
        artifact_paths=[rendered_pdf, *page_images],
        target_surface="page",
        target_identifier="page-review",
        target_region="pages 1-2",
        blast_radius="pages 1-2",
        neighbors="adjacent page surfaces",
        checks="rendered page review",
        summary="rendered page review ok",
    )
    make_review_evidence(
        para_ev,
        evidence_type="paragraph-review",
        task_mode=task_mode,
        reviewed_output=review_copy,
        artifact_paths=[rendered_pdf, *page_images],
        target_surface="paragraph",
        target_identifier="p-1",
        target_region="page 1 para 1",
        blast_radius="page 1",
        neighbors="adjacent paragraph",
        checks="paragraph review",
        summary="paragraph review ok",
    )
    make_review_evidence(
        touched_ev,
        evidence_type="touched-page-review",
        task_mode=task_mode,
        reviewed_output=review_copy,
        artifact_paths=[rendered_pdf, *page_images],
        target_surface="blast radius",
        target_identifier="pages-1-2",
        target_region="pages 1-2",
        blast_radius="pages 1-2",
        neighbors="adjacent page surfaces",
        checks="touched-page review",
        summary="touched-page review ok",
    )
    make_review_evidence(
        figure_ev,
        evidence_type="figure-review",
        task_mode=task_mode,
        reviewed_output=review_copy,
        artifact_paths=[rendered_pdf, *page_images],
        target_surface="figure",
        target_identifier="figure-1",
        target_region="page 1 figure block",
        blast_radius="page 1",
        neighbors="caption",
        checks="figure review",
        summary="figure review ok",
    )
    make_dummy_citation_audit_report(citation_audit, passed=True, document_path=review_copy)
    return review_copy, rendered_pdf, page_images, thesis_ev, para_ev, touched_ev, figure_ev, citation_audit


def existing_or_build_thesis_bundle(td: Path, task_mode: str) -> tuple[Path, Path, list[Path], Path, Path, Path, Path, Path]:
    """Reuse a selftest bundle when a case already created evidence for it.

    Several negative protected-surface cases intentionally create evidence
    first, then call a shared gate helper. Regenerating the same review-copy
    path inside that helper can change the DOCX package hash and mask the
    surface-specific failure the case is supposed to prove.
    """

    review_copy = td / "review_copy.docx"
    rendered_pdf = td / "rendered.pdf"
    page_images = [td / "pages" / "page-1.png", td / "pages" / "page-2.png"]
    thesis_ev = td / "render.md"
    para_ev = td / "paragraph.md"
    touched_ev = td / "touched.md"
    figure_ev = td / "figure.md"
    citation_audit = td / "citation_audit.md"
    required_paths = [review_copy, rendered_pdf, *page_images, thesis_ev, para_ev, touched_ev, figure_ev, citation_audit]
    if all(path.exists() for path in required_paths):
        return review_copy, rendered_pdf, page_images, thesis_ev, para_ev, touched_ev, figure_ev, citation_audit
    return build_thesis_bundle(td, task_mode)


