def case_skill_invocation_lock_blocked_rejected(td: Path) -> tuple[int, str]:
    record = make_skill_invocation_lock_selftest_record(td, "skill_invocation_lock_blocked")
    text = record.read_text(encoding="utf-8")
    match = re.search(r"^- skill invocation lock path: (.+)$", text, flags=re.MULTILINE)
    if not match:
        return 1, "skill invocation lock path missing in generated fixture"
    lock_path = Path(match.group(1).strip())
    lock_text = lock_path.read_text(encoding="utf-8")
    lock_text = lock_text.replace("- mutation allowed verdict: pass", "- mutation allowed verdict: blocked")
    lock_text = lock_text.replace("- final gate verdict: pass", "- final gate verdict: blocked")
    lock_path.write_text(lock_text, encoding="utf-8")
