def case_explicit_invocation_bootstrap_first_documented_valid(td: Path) -> tuple[int, str]:
    del td
    checks = {
        "SKILL.md": (
            SKILL_ROOT / "SKILL.md",
            [
                "## 0A. Explicit Invocation Bootstrap",
                "only then inspect project files",
                "If non-control action happened before the lock",
                "contaminated/reference-only drift",
            ],
        ),
        "user-feedback-persistence.md": (
            SKILL_ROOT / "references" / "user-feedback-persistence.md",
            [
                "EXEC-MAINT-072",
                "lock/checklist/audit bootstrap",
                "contaminated/reference-only drift",
            ],
        ),
        "maintenance-and-structure.md": (
            SKILL_ROOT / "references" / "user-feedback" / "maintenance-and-structure.md",
            [
                "### EXEC-MAINT-072. Explicit Invocation Bootstrap Must Precede Project Work",
                "Bootstrap actions are limited",
                "Project inspection, repository-wide text search",
                "current run is contaminated/reference-only drift",
                "`no non-control action before lock?`",
            ],
        ),
        "skill-invocation-lock-template.md": (
            SKILL_ROOT / "assets" / "skill-invocation-lock-template.md",
            [
                "- no non-control action before lock?:",
            ],
        ),
        "final-acceptance-template.md": (
            SKILL_ROOT / "assets" / "final-acceptance-template.md",
            [
                "- no non-control action before lock?:",
            ],
        ),
        "FILE-ROLE-INDEX.md": (
            SKILL_ROOT / "FILE-ROLE-INDEX.md",
            [
                "explicit-invocation bootstrap order",
                "EXEC-MAINT-072",
                "validate_skill_invocation_lock",
                "selftest coverage is in `scripts/selftest_skill_flow.py`",
            ],
        ),
    }
    errors: list[str] = []
    for label, (path, needles) in checks.items():
        text = path.read_text(encoding="utf-8")
        for needle in needles:
            if needle not in text:
                errors.append(f"{label} missing bootstrap-first phrase: {needle}")

    owner_map = json.loads((SKILL_ROOT / "references" / "rule-owner-map.json").read_text(encoding="utf-8"))
    rule = next((r for r in owner_map.get("rules", []) if r.get("id") == "EXEC-MAINT-072"), None)
    if not rule:
        errors.append("rule-owner-map missing EXEC-MAINT-072")
    else:
        expected_owner = "references/user-feedback/maintenance-and-structure.md"
        if rule.get("owner_file") != expected_owner:
            errors.append(f"EXEC-MAINT-072 owner_file must be {expected_owner}")
        if not rule.get("enforcement_required"):
            errors.append("EXEC-MAINT-072 must be enforcement_required")
        validators = rule.get("validator_owner") or []
        if "scripts/validate_skill_gate_record_gate.py::validate_skill_invocation_lock" not in validators:
            errors.append("EXEC-MAINT-072 must name validate_skill_invocation_lock as validator owner")
        owners = rule.get("selftest_owner") or []
        if "scripts/selftest_skill_flow.py::case_explicit_invocation_bootstrap_first_documented_valid" not in owners:
            errors.append("EXEC-MAINT-072 must name its bootstrap selftest owner")
        if "scripts/selftest_skill_flow.py::case_explicit_invocation_bootstrap_non_control_before_lock_rejected" not in owners:
            errors.append("EXEC-MAINT-072 must name its negative non-control-before-lock selftest owner")
        if "contaminated/reference-only drift" not in " ".join(rule.get("required_keywords", [])):
            errors.append("EXEC-MAINT-072 required_keywords must include contaminated/reference-only drift")
        if "skill-maintenance" not in rule.get("required_load_modes", []):
            errors.append("EXEC-MAINT-072 must load for skill-maintenance")
        if "no non-control action before lock?" not in rule.get("acceptance_fields", []):
            errors.append("EXEC-MAINT-072 acceptance_fields must include no non-control action before lock?")

    if errors:
        return 1, "\n".join(errors)
    return 0, "explicit invocation bootstrap-first rule is wired"


def case_rule_owner_hard_closure_missing_rejected(td: Path) -> tuple[int, str]:
    del td
    from validate_skill_gate_bundle import check_required_rule_owner_closures

    weak_rules = {
        "EXEC-MAINT-072": {"validator_owner": [], "selftest_owner": [], "acceptance_fields": []},
        "FMT-TOC-002": {"validator_owner": [], "selftest_owner": [], "required_keywords": []},
        "FB-LAYOUT-069": {"validator_owner": [], "selftest_owner": [], "required_load_modes": []},
    }
    issues = check_required_rule_owner_closures(weak_rules)
    ok = (
        any("EXEC-MAINT-072 missing hard-required validator_owner" in issue for issue in issues)
        and any("FMT-TOC-002 missing hard-required validator_owner" in issue for issue in issues)
        and any("FB-LAYOUT-069 missing hard-required validator_owner" in issue for issue in issues)
    )
    return (0 if ok else 1, "\n".join(issues))


