def make_review_artifact_gate_record(td: Path, stem: str) -> Path:
    review_copy, rendered_pdf, page_images, thesis_ev, para_ev, touched_ev, figure_ev, citation_audit = build_thesis_bundle(td, "thesis-only")
    format_task = td / f"{stem}_format_task.md"
    make_format_repair_task(
        format_task,
        review_copy=review_copy,
        thesis_paths=[thesis_ev],
        paragraph_paths=[para_ev],
        touched_paths=[touched_ev],
        citation_audit_path=citation_audit,
        rendered_pdf=rendered_pdf,
        page_images=page_images,
        touched_blocks="citation-bearing body paragraphs with comments",
        format_classes="body paragraph formatting; review artifacts; citation lane",
        sentinels="page 1",
        pages_to_inspect="1-2",
    )
    record = td / f"{stem}.acceptance.md"
    make_gate_record(
        record,
        task_mode="thesis-only",
        subtask=stem,
        output_path=review_copy,
        format_task_path=str(format_task),
        rendered_pdf=str(rendered_pdf),
        page_images="; ".join(str(p) for p in page_images),
        citation_audit_path=str(citation_audit),
        thesis_paths=str(thesis_ev),
        figure_paths=str(figure_ev),
        paragraph_paths=str(para_ev),
        touched_page_paths=str(touched_ev),
        renderer_path=str(PYTHON_EXE),
        rasterizer_path=str(PYTHON_EXE),
        review_copy_path=str(review_copy),
        humanizer_route_decision="humanizer-zh",
        humanizer_target_language="zh",
        humanizer_scope="chinese body rewrite",
        humanizer_evidence_path="AUTO",
    )
    return record


def make_preservation_gate_record_for_docs(
    td: Path,
    stem: str,
    *,
    source_docx: Path,
    final_docx: Path,
    citation_audit_path: Path | None = None,
    selected_thesis_workflow: str = "local-surface-repair",
    citation_preservation_scope: str = "local-surface-preservation",
) -> Path:
    rendered_pdf = make_pdf_with_text(td / f"{stem}.rendered.pdf", "1 Introduction\nBody evidence")
    page_images = [
        make_png_file(td / f"{stem}-pages" / "page-1.png"),
        make_png_file(td / f"{stem}-pages" / "page-2.png"),
    ]
    review_inventory = td / f"{stem}.source_review_artifacts.md"
    review_diff = td / f"{stem}.final_review_artifact_diff.md"
    citation_inventory = td / f"{stem}.source_body_citation_runs.md"
    citation_diff = td / f"{stem}.final_body_citation_run_diff.md"
    write_docx_preservation_reports_for_selftest(
        source_docx=source_docx,
        final_docx=final_docx,
        source_review_artifact_inventory_path=review_inventory,
        final_review_artifact_diff_path=review_diff,
        source_body_citation_run_inventory_path=citation_inventory,
        final_body_citation_run_diff_path=citation_diff,
        citation_preservation_scope=citation_preservation_scope,
    )
    citation_audit = citation_audit_path or td / f"{stem}.citation_audit.md"
    if citation_audit_path is None:
        make_dummy_citation_audit_report(citation_audit, passed=True, document_path=final_docx)

    common_evidence = {
        "task_mode": "thesis-only",
        "reviewed_output": final_docx,
        "artifact_paths": [rendered_pdf, *page_images],
        "source_review_artifact_inventory_path": str(review_inventory),
        "final_review_artifact_diff_path": str(review_diff),
        "source_body_citation_run_inventory_path": str(citation_inventory),
        "final_body_citation_run_diff_path": str(citation_diff),
        "citation_audit_final_docx_sha256": file_sha256(final_docx),
        "citation_audit_source_to_final_run_diff_path": str(citation_diff),
    }
    thesis_ev = td / f"{stem}.render.md"
    para_ev = td / f"{stem}.paragraph.md"
    touched_ev = td / f"{stem}.touched.md"
    figure_ev = td / f"{stem}.figure.md"
    make_review_evidence(
        thesis_ev,
        evidence_type="thesis-rendered-page",
        target_surface="page",
        target_identifier="page-review",
        target_region="pages 1-2",
        blast_radius="pages 1-2",
        neighbors="adjacent page surfaces",
        checks="source-to-final preservation review",
        summary="source-to-final preservation reports attached",
        **common_evidence,
    )
    make_review_evidence(
        para_ev,
        evidence_type="paragraph-review",
        target_surface="paragraph",
        target_identifier="p-1",
        target_region="page 1 para 1",
        blast_radius="page 1",
        neighbors="adjacent paragraph",
        checks="paragraph review",
        summary="paragraph review ok",
        **common_evidence,
    )
    make_review_evidence(
        touched_ev,
        evidence_type="touched-page-review",
        target_surface="blast radius",
        target_identifier="pages-1-2",
        target_region="pages 1-2",
        blast_radius="pages 1-2",
        neighbors="adjacent page surfaces",
        checks="touched-page review",
        summary="touched-page review ok",
        **common_evidence,
    )
    make_review_evidence(
        figure_ev,
        evidence_type="figure-review",
        target_surface="figure",
        target_identifier="figure-1",
        target_region="page 1 figure block",
        blast_radius="page 1",
        neighbors="caption",
        checks="figure review",
        summary="figure review ok",
        **common_evidence,
    )

    format_task = td / f"{stem}.format_task.md"
    make_format_repair_task(
        format_task,
        review_copy=final_docx,
        thesis_paths=[thesis_ev],
        paragraph_paths=[para_ev],
        touched_paths=[touched_ev],
        citation_audit_path=citation_audit,
        rendered_pdf=rendered_pdf,
        page_images=page_images,
        touched_blocks="citation-bearing body paragraphs with protected review artifacts",
        format_classes="body paragraph formatting; review artifacts; citation lane",
        sentinels="page 1",
        pages_to_inspect="1-2",
        source_review_artifact_inventory_path=str(review_inventory),
        final_review_artifact_diff_path=str(review_diff),
        source_body_citation_run_inventory_path=str(citation_inventory),
        final_body_citation_run_diff_path=str(citation_diff),
        citation_audit_final_docx_sha256=file_sha256(final_docx),
        citation_audit_source_to_final_run_diff_path=str(citation_diff),
    )
    record = td / f"{stem}.acceptance.md"
    make_gate_record(
        record,
        task_mode="thesis-only",
        subtask=stem,
        output_path=final_docx,
        format_task_path=str(format_task),
        rendered_pdf=str(rendered_pdf),
        page_images="; ".join(str(p) for p in page_images),
        citation_audit_path=str(citation_audit),
        thesis_paths=str(thesis_ev),
        figure_paths=str(figure_ev),
        paragraph_paths=str(para_ev),
        touched_page_paths=str(touched_ev),
        renderer_path=str(PYTHON_EXE),
        rasterizer_path=str(PYTHON_EXE),
        review_copy_path=str(final_docx),
        humanizer_route_decision="humanizer-zh",
        humanizer_target_language="zh",
        humanizer_scope="chinese body rewrite",
        humanizer_evidence_path="AUTO",
        source_review_artifact_inventory_path=str(review_inventory),
        final_review_artifact_diff_path=str(review_diff),
        source_body_citation_run_inventory_path=str(citation_inventory),
        final_body_citation_run_diff_path=str(citation_diff),
        citation_audit_final_docx_sha256=file_sha256(final_docx),
        citation_audit_source_to_final_run_diff_path=str(citation_diff),
        selected_thesis_workflow=selected_thesis_workflow,
    )
    return record


def case_review_artifact_inventory_missing_rejected(td: Path) -> tuple[int, str]:
    record = make_review_artifact_gate_record(td, "review_artifact_inventory_missing")
    text = record.read_text(encoding="utf-8")
    text = re.sub(
        r"(?m)^- source review-artifact inventory path: .*$",
        "- source review-artifact inventory path: none",
        text,
        count=1,
    )
    write_text(record, text)
    proc = run_validator(record)
    return proc.returncode, proc.stdout


