def make_comment_disposal_fixture(td: Path, stem: str) -> tuple[Path, Path, Path, Path, Path]:
    source = make_minimal_review_docx(td / f"{stem}-source.docx")
    add_comments_with_extended(source, [("Teacher approved removing this resolved comment from the clean final.", False)])
    add_comment_anchor_to_first_paragraph(source)
    final = make_minimal_review_docx(td / f"{stem}-final.docx")
    approval = td / f"{stem}-approval.md"
    write_text(approval, "- explicit user approval: clean final may remove resolved Word comments\n")
    evidence = td / f"{stem}-resolution-evidence.md"
    write_text(evidence, "- comment resolution checked before clean final disposal\n")
    ledger = td / f"{stem}-comment-resolution-ledger.json"
    write_text(
        ledger,
        json.dumps(
            {
                "schema": "graduation-project-builder.comment-resolution-ledger.v1",
                "source_docx_path": str(source),
                "source_docx_sha256": file_sha256(source),
                "final_docx_path": str(final),
                "final_docx_sha256": file_sha256(final),
                "claim_scope": "all-comments-resolved",
                "comments": [
                    {
                        "comment_id": "1",
                        "status": "removed-user-approved",
                        "evidence_path": str(evidence),
                        "approval_evidence_path": str(approval),
                    }
                ],
            },
            ensure_ascii=False,
            indent=2,
        )
        + "\n",
    )
    return source, final, ledger, approval, evidence


def run_review_artifact_audit_with_ledger(
    td: Path,
    stem: str,
    *,
    source_docx: Path,
    final_docx: Path,
    ledger: Path,
) -> subprocess.CompletedProcess[str]:
    return subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "audit_docx_review_artifacts.py"),
            "--source-docx",
            str(source_docx),
            "--final-docx",
            str(final_docx),
            "--review-inventory-report",
            str(td / f"{stem}.source-review.md"),
            "--review-diff-report",
            str(td / f"{stem}.final-review-diff.md"),
            "--citation-inventory-report",
            str(td / f"{stem}.source-citation.md"),
            "--citation-diff-report",
            str(td / f"{stem}.final-citation-diff.md"),
            "--comment-resolution-ledger",
            str(ledger),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )


