def case_review_comments_removed_invalid_resolution_ledger_rejected(td: Path) -> tuple[int, str]:
    source, final, ledger, _approval, _evidence = make_comment_disposal_fixture(td, "review-comments-ledger-invalid")
    proc = run_review_artifact_audit_with_ledger(
        td,
        "review-comments-ledger-invalid",
        source_docx=source,
        final_docx=final,
        ledger=ledger,
    )
    if proc.returncode != 0:
        return proc.returncode, proc.stdout + proc.stderr
    payload = json.loads(ledger.read_text(encoding="utf-8"))
    payload["source_docx_sha256"] = "0" * 64
    write_text(ledger, json.dumps(payload, ensure_ascii=False, indent=2) + "\n")
    issues = validate_review_artifact_reports(
        td / "review-comments-ledger-invalid.source-review.md",
        td / "review-comments-ledger-invalid.final-review-diff.md",
        expected_final_docx=final,
    )
    return (0 if any("comment disposal authorization failed" in item for item in issues) else 1, "\n".join(issues))


