def case_acceptance_generator_passes_source_docx_to_figure_contract(td: Path) -> tuple[int, str]:
    fixture = prepare_toc_acceptance_generator_fixture(td)
    root = Path(fixture["root"])
    source_png = make_png(root / "acceptance-source-media.png", 1200, 800, fill="white")
    final_png = make_png(root / "acceptance-final-media.png", 1200, 800, fill="#f8fafc")
    source_docx = make_body_picture_docx(root / "acceptance-source.docx", source_png, caption="\u56fe5-1 \u7cfb\u7edf\u9996\u9875")
    final_docx = copy_docx_replacing_media(source_docx, root / "acceptance-final.docx", final_png)
    shutil.copyfile(final_docx, Path(fixture["template_docx"]))
    fixture["source_docx"] = source_docx
    fixture["final_docx"] = final_docx
    fixture["transaction_record"] = make_thesis_transaction_record(root / "acceptance-source-docx.transaction.json", final_docx=final_docx)
    make_sample_self_check_pass_report(Path(fixture["self_check"]), document_path=final_docx)
    make_dummy_citation_audit_report(Path(fixture["citation_audit"]), passed=True, document_path=final_docx)
    make_docx_font_audit_report(Path(fixture["font_audit"]), passed=True, docx_path=final_docx)
    make_docx_body_style_audit_report(
        Path(fixture["body_style_audit"]),
        passed=True,
        reference_docx_path=Path(fixture["template_docx"]),
        final_docx_path=final_docx,
    )
    write_toc_geometry_json(
        Path(fixture["toc_geometry_json"]),
        root / "template-toc.png",
        root / "actual-toc.png",
        template_docx=Path(fixture["template_docx"]),
        final_docx=final_docx,
    )
    write_whole_pagination_json(Path(fixture["whole_pagination_json"]), template_docx=Path(fixture["template_docx"]), final_docx=final_docx)
    manifest = add_docx_binding_fields(runtime_figure_manifest(root, final_png), source_docx=source_docx, final_docx=final_docx)
    manifest["figures"]["fig_5_1"].update(  # type: ignore[index]
        figure_manifest_common_evidence(root, "acceptance-source-docx", "\u56fe5-1 \u7cfb\u7edf\u9996\u9875", final_png)
    )
    manifest["source_docx_sha256"] = "0" * 64
    manifest_path = root / "acceptance-figure-manifest.json"
    write_text(manifest_path, json.dumps(manifest, ensure_ascii=False, indent=2) + "\n")
    fixture["asset_manifest"] = manifest_path
    output = root / "acceptance-source-docx.acceptance.md"
    proc = run_acceptance_generator_for_fixture(fixture, output)
    combined = (proc.stdout or "") + (proc.stderr or "") + ("\n" + output.read_text(encoding="utf-8", errors="replace") if output.exists() else "")
    ok = proc.returncode != 0 and "source_docx_sha256 does not match source DOCX" in combined
    return (0 if ok else 1), combined


