def case_template_discovery_script_valid(td: Path) -> tuple[int, str]:
    make_dummy_file(td / "thesis-template.docx")
    make_dummy_file(td / "draft-output.docx")
    report = td / "template_discovery.json"
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "discover_project_thesis_template.py"),
            "--project-root",
            str(td),
            "--output",
            str(report),
            "--fail-on-none",
        ],
            capture_output=True,
            text=True,
            encoding="utf-8",
            errors="replace",
            timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )
    return proc.returncode, (proc.stdout or "") + (proc.stderr or "")


def case_template_discovery_prefers_format_template_over_repair_outputs(td: Path) -> tuple[int, str]:
    expected = make_dummy_file(td / "格式模板.doc")
    make_dummy_file(td / "论文格式修复-pass024.docx")
    make_dummy_file(td / "基于Spring Boot的在线学习资源共享平台设计与实现-格式对齐版.docx")
    make_dummy_file(td / "format-repair-run-20260501-190642-structure-toc" / "review-pass-028.docx")
    make_dummy_file(td / "format-repair-run-20260501-190642-structure-toc" / "stage" / "格式模板.docx")
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "discover_project_thesis_template.py"),
            "--project-root",
            str(td),
            "--fail-on-none",
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )
    out = (proc.stdout or "") + (proc.stderr or "")
    if proc.returncode != 0:
        return proc.returncode, out
    try:
        report = json.loads(proc.stdout)
    except json.JSONDecodeError as exc:
        return 1, f"template discovery JSON parse failed: {exc}\n{out}"
    selected = Path(str(report.get("selected_template_path", "")))
    if selected != expected:
        return 1, f"selected_template_name={selected.name}; expected={expected.name}\n{out}"
    return 0, f"selected_template_name={selected.name}\n{out}"


