def make_humanizer_evidence_missing_line(path: Path, missing_prefix: str) -> str:
    make_humanizer_evidence(
        path,
        skill_name="humanizer-zh",
        target_language="zh",
        paragraph_id="zh-body-p001",
        before_text="\u672c\u6587\u6df1\u5165\u63a2\u8ba8\u7cfb\u7edf\u4ef7\u503c\u3002",
        after_text="\u672c\u6587\u8bf4\u660e\u7cfb\u7edf\u8bbe\u8ba1\u3001\u5b9e\u73b0\u548c\u9a8c\u8bc1\u8303\u56f4\u3002",
    )
    lines = [
        line for line in path.read_text(encoding="utf-8").splitlines()
        if not line.startswith(missing_prefix)
    ]
    path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    return str(path)


