def make_valid_agent_consistency_gate_record(td: Path, stem: str) -> Path:
    review_copy, rendered_pdf, page_images, thesis_ev, para_ev, touched_ev, figure_ev, citation_audit = build_thesis_bundle(td, "thesis-only")
    format_task = td / f"{stem}_format_task.md"
    make_format_repair_task(
        format_task,
        review_copy=review_copy,
        thesis_paths=[thesis_ev],
        paragraph_paths=[para_ev],
        touched_paths=[touched_ev],
        citation_audit_path=citation_audit,
        rendered_pdf=rendered_pdf,
        page_images=page_images,
        touched_blocks="full protected-surface evidence consistency",
        format_classes="TOC geometry; TOC paragraph typography; whole-document pagination",
        sentinels="TOC; whole_document_pagination",
        pages_to_inspect="front matter and all rendered pages",
    )
    record = td / f"{stem}.acceptance.md"
    make_gate_record(
        record,
        task_mode="thesis-only",
        subtask="agent protected evidence consistency",
        output_path=review_copy,
        format_task_path=str(format_task),
        rendered_pdf=str(rendered_pdf),
        page_images="; ".join(str(p) for p in page_images),
        citation_audit_path=str(citation_audit),
        thesis_paths=str(thesis_ev),
        figure_paths=str(figure_ev),
        paragraph_paths=str(para_ev),
        touched_page_paths=str(touched_ev),
        toc_restoration_paths=str(thesis_ev),
        toc_rendered_comparison_paths=str(thesis_ev),
        toc_baseline_restoration_summary="restored to locked baseline",
        toc_visual_rhythm_summary="matches locked TOC page rhythm",
        humanizer_route_decision="both",
        humanizer_target_language="zh+en",
        humanizer_scope="agent protected evidence consistency record",
        humanizer_evidence_path="AUTO",
        renderer_path=str(PYTHON_EXE),
        rasterizer_path=str(PYTHON_EXE),
        review_copy_path=str(review_copy),
    )
    return record


def case_agent_manifest_toc_geometry_mismatch_rejected(td: Path) -> tuple[int, str]:
    record = make_valid_agent_consistency_gate_record(td, "agent_manifest_toc_geometry_mismatch")
    manifest = record.with_suffix(".agent_run_manifest.md")
    text = manifest.read_text(encoding="utf-8")
    text = re.sub(
        r"(?m)^- toc_visual_geometry_evidence_paths: .*$",
        lambda _: f"- toc_visual_geometry_evidence_paths: {td / 'wrong-toc-geometry.md'}",
        text,
        count=1,
    )
    write_text(manifest, text)
    proc = run_validator(record)
    return proc.returncode, proc.stdout


def case_agent_task_card_whole_pagination_mismatch_rejected(td: Path) -> tuple[int, str]:
    record = make_valid_agent_consistency_gate_record(td, "agent_task_card_whole_pagination_mismatch")
