def case_final_acceptance_role_alias_mojibake_rejected(td: Path) -> tuple[int, str]:
    record = make_valid_agent_consistency_gate_record(td, "final_acceptance_role_alias_mojibake")
    bad_aliases = "总控 内容 格式 图表 引用 程序 验收 审核".encode("utf-8").decode("gbk", errors="replace")
    bad_map = (
        f"controller={bad_aliases} content-worker={bad_aliases} format-worker={bad_aliases} "
        f"figure-worker={bad_aliases} citation-worker={bad_aliases} program-worker={bad_aliases} "
        f"acceptance-worker={bad_aliases} audit={bad_aliases}"
    )
    replacements = {
        "- agent role aliases zh:": bad_aliases,
        "- required lane aliases zh:": bad_aliases,
        "- lane alias map zh:": bad_map,
        "- audit role alias zh:": bad_aliases,
    }
    text = record.read_text(encoding="utf-8")
    for prefix, value in replacements.items():
        text = re.sub(rf"(?m)^{re.escape(prefix)} .*$", f"{prefix} {value}", text, count=1)
    write_text(record, text)
    proc = run_validator(record)
    return proc.returncode, proc.stdout


