    write_text(
        manifest,
        textwrap.dedent(
            f"""\
            # Agent Run Manifest Template

            ## Run Fields
            - run_id: agent-single-no-auth-positive
            - task_mode: thesis-only
            - subtask: positive single-agent-no-auth fixture
            - authorization_source: none
            - agent_mode: single-agent-no-auth
            - max_concurrent_live_agents: 1
            - live_agent_count_plan: single controller executor plus sequential audit fallback; no spawned workers
            - dispatch_wave_plan: single-agent-no-auth wave: controller executes; audit role runs as sequential-audit-fallback
            - audit_presence_by_wave: single-agent-no-auth wave includes audit=sequential-audit-fallback
            - concurrency_limit_verdict: pass
            - required_lanes: controller; audit
            - role_alias_map_zh: 总控controller-audit-role; 审核controller-audit-role
            - lane_alias_map_zh: controller=总控 audit=审核
            - required_lane_aliases_zh: 总控 审核
            - spawned_agent_aliases_zh: none
            - controller_role_alias_zh: 总控
            - worker_role_aliases_zh: none
            - audit_role_alias_zh: 审核
            - spawn_attempted: no
            - spawned_agent_ids: none
            - sequential_fallback_reason: no explicit user authorization, so no spawned-agent claim
            - audit_agent_id: controller-audit-role
            - audit_verdict: pass
            - handoff_status: pass
            - notes: selftest positive fixture

            ## Dispatch Evidence
            - controller_lane: controller-audit-role
            - worker_lanes: worker-skipped-single-no-auth
            - audit_lane: controller-audit-role
            - system_agent_id_alias_map: controller-audit-role=总控审核
            - lane_task_card_paths: {controller_card}; {worker_card}; {audit_card}
            - evidence_paths: {acceptance}; {controller_card}; {worker_card}; {audit_card}

            ## Handoff Notes
            - final_status: pass
            - blocker_summary: none
            - skipped_lanes_with_reasons: worker spawn skipped because authorization_source is none; skipped worker is recorded by {worker_card}
            """
        ),
    )
    write_text(
        acceptance,
        textwrap.dedent(
            f"""\
            # Final Acceptance Template

            ## Condition Locks
            - agent authorization source: none
            - agent mode: single-agent-no-auth
            - max concurrent live agents: 1
            - live agent count plan: single controller executor plus sequential audit fallback; no spawned workers
            - dispatch wave plan: single-agent-no-auth wave: controller executes; audit role runs as sequential-audit-fallback
            - audit presence by wave: single-agent-no-auth wave includes audit=sequential-audit-fallback
            - concurrency limit verdict: pass
            - required lanes: controller; audit
            - agent role aliases zh: 总控 审核
            - required lane aliases zh: 总控 审核
            - spawned agent aliases zh: none
            - lane alias map zh: controller=总控 audit=审核
            - audit role alias zh: 审核
            - spawned agent ids: none
            - audit agent id: controller-audit-role
            - audit verdict: pass
            - sequential fallback reason: no explicit user authorization, so no spawned-agent claim

            ## Verification Evidence
            - agent run manifest path: {manifest}
            - lane task card evidence paths: {controller_card}; {worker_card}; {audit_card}
            - agent id alias map: controller-audit-role=总控审核
            """
        ),
    )
    combined = (
        manifest.read_text(encoding="utf-8")
        + "\n"
        + acceptance.read_text(encoding="utf-8")
        + "\n"
        + controller_card.read_text(encoding="utf-8")
        + "\n"
        + worker_card.read_text(encoding="utf-8")
        + "\n"
        + audit_card.read_text(encoding="utf-8")
    )
    required = [
        "- authorization_source: none",
        "- agent_mode: single-agent-no-auth",
        "- max_concurrent_live_agents: 1",
        "- concurrency_limit_verdict: pass",
        "- role_alias_zh: 审核",
        "- lane_alias_zh: 审核",
        "- lane_alias_map_zh: controller=总控 audit=审核",
        "- required_lane_aliases_zh: 总控 审核",
        "- audit_role_alias_zh: 审核",
        "- required lane aliases zh: 总控 审核",
        "- lane alias map zh: controller=总控 audit=审核",
        "- audit role alias zh: 审核",
        "- agent id alias map:",
        "- spawned_agent_ids: none",
        "- sequential_fallback_reason: no explicit user authorization",
        "- audit_verdict: pass",
        "- agent mode: single-agent-no-auth",
        "- max concurrent live agents: 1",
        "- concurrency limit verdict: pass",
        "- agent run manifest path:",
        "- audit verdict: pass",
        str(controller_card),
        str(worker_card),
        str(audit_card),
    ]
    missing = [token for token in required if token not in combined]
    if missing:
        return 1, "missing single-agent-no-auth record tokens: " + "; ".join(missing)
    return 0, "single-agent-no-auth record accepted\n" + combined


