def case_duplicate_registry_rejected(td: Path) -> tuple[int, str]:
    copied = td / "skill_copy"
    shutil.copytree(SKILL_ROOT, copied)
    registry = copied / "scripts" / "validate_skill_gate_registry_bundle.py"
    text = registry.read_text(encoding="utf-8")
    marker = "'assets/format-repair-task-template.md': ["
    insert = """'assets/format-repair-task-template.md': [
        "DUPLICATE",
    ],
"""
    idx = text.find(marker)
    text = text[:idx] + insert + text[idx:]
    registry.write_text(text, encoding="utf-8")
    proc = run_validator_for_skill_root(copied)
    return proc.returncode, (proc.stdout or "") + (proc.stderr or "")


