def remove_record_prefixes(path: Path, prefixes: tuple[str, ...]) -> None:
    text = path.read_text(encoding="utf-8")
    kept = [
        line
        for line in text.splitlines()
        if not any(line.strip().lower().startswith(prefix.lower()) for prefix in prefixes)
    ]
    write_text(path, "\n".join(kept) + "\n")


def replace_record_prefixes(path: Path, replacements: dict[str, str]) -> None:
    lines: list[str] = []
    for line in path.read_text(encoding="utf-8").splitlines():
        replaced = False
        for prefix, value in replacements.items():
            if line.strip().lower().startswith(prefix.lower()):
                lines.append(f"{prefix} {value}")
                replaced = True
                break
        if not replaced:
            lines.append(line)
    write_text(path, "\n".join(lines) + "\n")


