def case_protected_english_keyword_colon_split_valid(td: Path) -> tuple[int, str]:
    from validate_skill_gate_record_evidence import _keyword_signature_from_docx

    good_docx = make_raw_docx(
        td / "english-keyword-colon-good.docx",
        '''
    <w:p><w:r><w:t>Abstract</w:t></w:r></w:p>
    <w:p><w:r><w:t>English abstract paragraph.</w:t></w:r></w:p>
    <w:p>
      <w:r><w:rPr><w:b/></w:rPr><w:t>Key Words</w:t></w:r>
      <w:r><w:rPr><w:b/></w:rPr><w:t>:</w:t></w:r>
      <w:r><w:t> network automation; Python; Flask</w:t></w:r>
    </w:p>
    <w:p><w:r><w:t>Contents</w:t></w:r></w:p>
''',
    )
    bad_docx = make_raw_docx(
        td / "english-keyword-colon-bad.docx",
        '''
    <w:p><w:r><w:t>Abstract</w:t></w:r></w:p>
    <w:p><w:r><w:t>English abstract paragraph.</w:t></w:r></w:p>
    <w:p>
      <w:r><w:rPr><w:b/></w:rPr><w:t>Key Words</w:t></w:r>
      <w:r><w:t>: network automation; Python; Flask</w:t></w:r>
    </w:p>
    <w:p><w:r><w:t>Contents</w:t></w:r></w:p>
''',
    )
    good_signature, good_issues = _keyword_signature_from_docx(good_docx, "en_keyword_line")
    _bad_signature, bad_issues = _keyword_signature_from_docx(bad_docx, "en_keyword_line")
    ok = (
        not good_issues
        and str(good_signature.get("labelText")) == "Key Words:"
        and any("content run count" in item or "label-only" in item for item in bad_issues)
    )
    details = "GOOD=" + json.dumps(good_signature, ensure_ascii=False) + "\nGOOD_ISSUES=" + "\n".join(good_issues) + "\nBAD_ISSUES=" + "\n".join(bad_issues)
    return (0 if ok else 1, details)


