def _rewrite_docx_document_xml(docx_path: Path, transform) -> None:
    with zipfile.ZipFile(docx_path, "r") as zin:
        members = {name: zin.read(name) for name in zin.namelist()}
    members["word/document.xml"] = transform(members["word/document.xml"])
    with zipfile.ZipFile(docx_path, "w", zipfile.ZIP_DEFLATED) as zout:
        for name, data in members.items():
            zout.writestr(name, data)


def _rewrite_docx_styles_xml(docx_path: Path, transform) -> None:
    with zipfile.ZipFile(docx_path, "r") as zin:
        members = {name: zin.read(name) for name in zin.namelist()}
    members["word/styles.xml"] = transform(members["word/styles.xml"])
    with zipfile.ZipFile(docx_path, "w", zipfile.ZIP_DEFLATED) as zout:
        for name, data in members.items():
            zout.writestr(name, data)


