def case_audit_body_style_narrative_figure_reference_checked_as_body(td: Path) -> tuple[int, str]:
    from audit_docx_body_style import audit_body_style
    from xml.etree import ElementTree as ET

    narrative = "图3-1展示了系统处理流程，说明模型输出如何进入业务模块。这与第三章说明的规则保持一致，该段是正文说明而不是图题。"
    caption = "图3-1 系统处理流程图"
    ns = {"w": "http://schemas.openxmlformats.org/wordprocessingml/2006/main"}
    w = "{http://schemas.openxmlformats.org/wordprocessingml/2006/main}"
    reference = make_body_instance_drift_docx(td / "figure-reference-body-reference.docx", keep_instance_metrics=True)
    final = make_body_instance_drift_docx(td / "figure-reference-body-final.docx", keep_instance_metrics=True)

    def rewrite_fixture(docx_path: Path, *, strip_narrative_metrics: bool) -> None:
        with zipfile.ZipFile(docx_path, "r") as zin:
            members = {name: zin.read(name) for name in zin.namelist()}
        document_xml = members["word/document.xml"].decode("utf-8")
        document_xml = document_xml.replace("Body paragraph one.", narrative)
        document_xml = document_xml.replace("Body paragraph two.", caption)
        if strip_narrative_metrics:
            root = ET.fromstring(document_xml)
            for paragraph in root.findall(".//w:p", ns):
                text = "".join(node.text or "" for node in paragraph.findall(".//w:t", ns))
                if text != narrative:
                    continue
                ppr = paragraph.find("w:pPr", ns)
                if ppr is not None:
                    paragraph.remove(ppr)
                new_ppr = ET.Element(w + "pPr")
                pstyle = ET.SubElement(new_ppr, w + "pStyle")
                pstyle.set(w + "val", "Normal")
                paragraph.insert(0, new_ppr)
                break
            document_xml = ET.tostring(root, encoding="utf-8", xml_declaration=True).decode("utf-8")
        members["word/document.xml"] = document_xml.encode("utf-8")
        with zipfile.ZipFile(docx_path, "w", zipfile.ZIP_DEFLATED) as zout:
            for name, data in members.items():
                zout.writestr(name, data)

    rewrite_fixture(reference, strip_narrative_metrics=False)
    rewrite_fixture(final, strip_narrative_metrics=True)
    report, _binding, _baseline, _family, body_issues = audit_body_style(
        reference,
        final,
        strict_direct_visible_metrics=True,
    )
    combined = "\n".join(body_issues)
    ok = (
        "图3-1展示" in combined
        and "paragraph p3 lacks direct visible metrics" in combined
        and "figure-caption paragraph" in combined
    )
    return (0 if ok else 1, report + "\n" + combined)


