def case_repair_docx_caption_adjacent_body_repairs_second_inserted_body(td: Path) -> tuple[int, str]:
    from audit_docx_body_style import caption_sibling_body_contamination_records

    source = make_body_instance_drift_docx(td / "caption-adjacent-source.docx", keep_instance_metrics=True)
    output = td / "caption-adjacent-output.docx"
    report = td / "caption-adjacent-report.json"
    donor_text = (
        "\u672c\u6bb5\u4f5c\u4e3a\u4fee\u590d\u5de5\u5177\u7684\u6b63\u6587\u6837\u672c\uff0c"
        "\u7528\u4e8e\u63d0\u4f9b\u6bb5\u843d\u7f29\u8fdb\u3001\u884c\u8ddd\u3001\u5bf9\u9f50"
        "\u65b9\u5f0f\u548c\u8fd0\u884c\u5b57\u4f53\u5c5e\u6027\u7684\u5c40\u90e8\u6350\u732e"
        "\u57fa\u7ebf\uff0c\u907f\u514d\u56fe\u9898\u6837\u5f0f\u6c61\u67d3\u65b0\u63d2\u5165"
        "\u8bf4\u660e\u6bb5\u843d\u3002"
    )
    caption = "\u56fe5-1 \u68c0\u6d4b\u524d\u540e\u7ed3\u679c\u5bf9\u6bd4"
    first_polluted = (
        "\u56fe5-1\u663e\u793a\u4e86\u7cfb\u7edf\u68c0\u6d4b\u524d\u540e\u7684"
        "\u8f66\u8f86\u8fb9\u754c\u6846\u5bf9\u6bd4\u7ed3\u679c\u3002"
    )
    second_polluted = (
        "\u8be5\u6bb5\u4e3a\u65b0\u63d2\u5165\u7684\u7ed3\u679c\u8bf4\u660e\uff0c"
        "\u867d\u7136\u672a\u91cd\u590d\u56fe\u53f7\uff0c\u4f46\u539f\u59cb\u6bb5\u843d"
        "\u4ecd\u7ee7\u627f\u4e86\u56fe\u9898\u7684\u5c45\u4e2d\u3001\u96f6\u9996\u884c"
        "\u7f29\u8fdb\u548c\u504f\u5927\u5b57\u53f7\u3002"
    )
    following_heading = "2.3 \u540e\u7eed\u7ed3\u679c\u8bf4\u660e"

    def transform(raw: bytes) -> bytes:
        text = raw.decode("utf-8")
        text = text.replace("<w:t>Body paragraph one.</w:t>", f"<w:t>{donor_text}</w:t>", 1)
        caption_ppr = (
            '<w:pPr><w:spacing w:before="120" w:after="120" w:line="240" '
            'w:lineRule="auto"/><w:ind w:firstLine="0" w:left="0" w:right="0"/>'
            '<w:jc w:val="center"/></w:pPr>'
        )
        polluted_ppr = (
            '<w:pPr><w:pStyle w:val="Caption"/><w:keepNext/>'
            '<w:spacing w:before="120" w:after="120" w:line="240" w:lineRule="auto"/>'
            '<w:ind w:firstLine="0" w:left="0" w:right="0"/><w:jc w:val="center"/></w:pPr>'
        )
        return text.replace(
            '<w:p><w:pPr><w:pStyle w:val="Normal"/><w:spacing w:before="0" w:after="0" w:line="360" w:lineRule="auto"/><w:ind w:firstLine="420" w:left="0" w:right="0"/><w:jc w:val="both"/></w:pPr><w:r><w:t>Body paragraph two.</w:t></w:r></w:p>',
            f'<w:p>{caption_ppr}<w:r><w:rPr><w:sz w:val="21"/><w:szCs w:val="21"/></w:rPr><w:t>{caption}</w:t></w:r></w:p>'
            f'<w:p>{polluted_ppr}<w:r><w:rPr><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr><w:t>{first_polluted}</w:t></w:r></w:p>'
            f'<w:p>{polluted_ppr}<w:r><w:rPr><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr><w:t>{second_polluted}</w:t></w:r></w:p>'
            f'<w:p>{polluted_ppr}<w:r><w:rPr><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr><w:t>{following_heading}</w:t></w:r></w:p>',
        ).encode("utf-8")

    _rewrite_docx_document_xml(source, transform)
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "repair_docx_caption_adjacent_body.py"),
            "--input-docx",
            str(source),
            "--output-docx",
            str(output),
            "--max-nearby-body-paragraphs",
            "3",
            "--report-json",
            str(report),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=False,
        timeout=timeout_seconds(120),
    )
    report_text = report.read_text(encoding="utf-8", errors="replace") if report.exists() else ""
    payload = json.loads(report_text) if report_text.strip() else {}
    remaining = caption_sibling_body_contamination_records(output) if output.exists() else [{"missing": "output"}]
    ok = (
        proc.returncode == 0
        and payload.get("nearby_body_paragraph_limit") == 3
        and any(change.get("nearby_number") == 2 and change.get("caption_like_format_repaired") for change in payload.get("changes", []))
        and all(following_heading not in str(change.get("old_text_prefix", "")) for change in payload.get("changes", []))
        and "\\u56fe5-1" in report_text
        and "\u56fe5-1" not in report_text
        and not remaining
    )
    return (0 if ok else 1, (proc.stdout or "") + (proc.stderr or "") + report_text + "\nremaining=" + repr(remaining))


def case_audit_body_style_ignores_field_instr_text_valid(td: Path) -> tuple[int, str]:
    def inject_field_code_body_paragraph(docx_path: Path) -> None:
        with zipfile.ZipFile(docx_path, "r") as zin:
            members = {name: zin.read(name) for name in zin.namelist()}
        document_xml = members["word/document.xml"].decode("utf-8")
        body_ppr = (
            '<w:pPr><w:pStyle w:val="Normal"/><w:spacing w:before="0" w:after="0" '
            'w:line="360" w:lineRule="auto"/><w:ind w:firstLine="420" w:left="0" '
            'w:right="0"/><w:jc w:val="both"/></w:pPr>'
        )
        rpr = (
            '<w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" '
            'w:eastAsia="SimSun" w:cs="Times New Roman"/></w:rPr>'
        )
        field_body = (
            f'<w:p>{body_ppr}'
            f'<w:r>{rpr}<w:t>正文说明 </w:t></w:r>'
            f'<w:r>{rpr}<w:t>Transformer</w:t></w:r>'
            '<w:r><w:fldChar w:fldCharType="begin"/></w:r>'
            '<w:r><w:instrText xml:space="preserve"> HYPERLINK \\l "cite_ref_1" </w:instrText></w:r>'
            '<w:r><w:fldChar w:fldCharType="separate"/></w:r>'
            '<w:r><w:rPr><w:vertAlign w:val="superscript"/></w:rPr><w:t>[1]</w:t></w:r>'
            '<w:r><w:fldChar w:fldCharType="end"/></w:r>'
            f'<w:r>{rpr}<w:t>。</w:t></w:r>'
            '</w:p>'
        )
        document_xml = re.sub(
            r'<w:p><w:pPr><w:pStyle w:val="Normal"/><w:spacing[^>]+/><w:ind[^>]+/><w:jc w:val="both"/></w:pPr><w:r><w:t>Body paragraph one\.</w:t></w:r></w:p>',
            lambda _match: field_body,
            document_xml,
            count=1,
        )
        members["word/document.xml"] = document_xml.encode("utf-8")
        with zipfile.ZipFile(docx_path, "w", zipfile.ZIP_DEFLATED) as zout:
            for name, data in members.items():
                zout.writestr(name, data)

    reference_docx = make_body_instance_drift_docx(td / "body-field-reference.docx", keep_instance_metrics=True)
    final_docx = make_body_instance_drift_docx(td / "body-field-final.docx", keep_instance_metrics=True)
    inject_field_code_body_paragraph(reference_docx)
    inject_field_code_body_paragraph(final_docx)
    report = td / "body_field_instr_audit.md"
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "audit_docx_body_style.py"),
            "--reference-docx",
            str(reference_docx),
            "--final-docx",
            str(final_docx),
            "--report",
            str(report),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=False,
        timeout=timeout_seconds(120),
    )
    report_text = report.read_text(encoding="utf-8", errors="replace") if report.exists() else ""
    ok = proc.returncode == 0 and "result: pass" in report_text and "HYPERLINK" not in report_text
    return (0 if ok else 1, (proc.stdout or "") + report_text)


def _run_comment_content_repair_case(
    td: Path,
    *,
    plan_payload: dict[str, object],
    input_docx: Path | None = None,
    extra_args: list[str] | None = None,
) -> subprocess.CompletedProcess[str]:
    source = input_docx or make_minimal_review_docx(td / "comment-content-source.docx")
    plan = td / "comment-content-plan.json"
    report = td / "comment-content-report.json"
    output = td / "comment-content-output.docx"
    write_text(plan, json.dumps(plan_payload, ensure_ascii=False, indent=2) + "\n")
    command = [
        str(PYTHON_EXE),
        str(COMMENT_CONTENT_REPAIR_SCRIPT),
        "--input-docx",
        str(source),
        "--output-docx",
        str(output),
        "--plan",
        str(plan),
        "--report",
        str(report),
    ]
    if extra_args:
        command.extend(extra_args)
    return subprocess.run(
        command,
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )


def case_repair_comment_content_caption_sets_direct_font_size_valid(td: Path) -> tuple[int, str]:
    from docx import Document  # type: ignore

    caption = "表5-1  系统测试结果汇总"
    source = td / "caption-size-source.docx"
    document = Document()
    document.add_paragraph("目录")
    document.add_paragraph("1 Introduction")
    document.add_paragraph(caption)
    document.save(source)
    proc = _run_comment_content_repair_case(
        td,
        input_docx=source,
        plan_payload={
            "caption_format_repairs": [
                {
                    "contains_text": caption,
                    "line": "240",
                    "before": "120",
                    "after": "120",
                    "clear_bold": True,
                }
            ]
        },
    )
    if proc.returncode != 0:
        return proc.returncode, (proc.stdout or "") + (proc.stderr or "")
    output = td / "comment-content-output.docx"
    with zipfile.ZipFile(source, "r") as zf:
        source_rels = zf.read("word/_rels/document.xml.rels")
        source_types = zf.read("[Content_Types].xml")
    with zipfile.ZipFile(output, "r") as zf:
        output_rels = zf.read("word/_rels/document.xml.rels")
        output_types = zf.read("[Content_Types].xml")
        root = ET.fromstring(zf.read("word/document.xml"))
    ns = {"w": "http://schemas.openxmlformats.org/wordprocessingml/2006/main"}

    def w_attr(name: str) -> str:
        return f"{{{ns['w']}}}{name}"

    target = None
    for paragraph in root.findall(".//w:body/w:p", ns):
        text = "".join(node.text or "" for node in paragraph.findall(".//w:t", ns))
        if text == caption:
            target = paragraph
            break
    if target is None:
        return 1, "caption paragraph not found"
    ppr = target.find("./w:pPr", ns)
    jc = ppr.find("./w:jc", ns) if ppr is not None else None
    spacing = ppr.find("./w:spacing", ns) if ppr is not None else None
    sizes = [node.get(w_attr("val")) for node in target.findall(".//w:rPr/w:sz", ns)]
    complex_sizes = [node.get(w_attr("val")) for node in target.findall(".//w:rPr/w:szCs", ns)]
    ok = (
        jc is not None
        and jc.get(w_attr("val")) == "center"
        and spacing is not None
        and spacing.get(w_attr("line")) == "240"
        and sizes
        and all(size == "21" for size in sizes)
        and complex_sizes
        and all(size == "21" for size in complex_sizes)
        and output_rels == source_rels
        and output_types == source_types
    )
    return (
        0 if ok else 1,
        json.dumps(
            {
                "sizes": sizes,
                "szCs": complex_sizes,
                "rels_preserved": output_rels == source_rels,
                "content_types_preserved": output_types == source_types,
            },
            ensure_ascii=False,
        ),
    )


