def case_repair_comment_content_body_protected_surfaces_rejected(td: Path) -> tuple[int, str]:
    from docx import Document  # type: ignore

    protected_rows = [
        ("abstract", "Abstract body should not be normalized as body text."),
        ("keyword", "Key words: YOLOv8-Pose; detection"),
        ("toc", "\u76ee\u5f55"),
        ("reference", "[1] Reference entry"),
        ("acknowledgement", "\u81f4\u8c22"),
    ]
    outputs: list[str] = []
    for suffix, text in protected_rows:
        source = td / f"protected-{suffix}.docx"
        document = Document()
        document.add_paragraph("1 Introduction")
        document.add_paragraph(text)
        document.save(source)
        proc = _run_comment_content_repair_case(
            td / suffix,
            input_docx=source,
            plan_payload={
                "body_paragraph_format_repairs": [
                    {
                        "contains_text": text,
                        "style_id": "Normal",
                    }
                ]
            },
        )
        combined = (proc.stdout or "") + (proc.stderr or "")
        outputs.append(f"{suffix}: rc={proc.returncode}; {combined}")
        if proc.returncode == 0 or "not a body_text paragraph" not in combined:
            return 1, "\n".join(outputs)
    return 0, "\n".join(outputs)


def case_repair_comment_content_ascii_allowlist_scoped_valid(td: Path) -> tuple[int, str]:
    from docx import Document  # type: ignore
    from zipfile import ZipFile
    from xml.etree import ElementTree as ET

    source = td / "ascii-allowlist.docx"
    document = Document()
    document.add_paragraph("1 Introduction")
    document.add_paragraph("allowed ASCII YOLOv8 text")
    document.add_paragraph("blocked ASCII OpenCV text")
    document.save(source)
    proc = _run_comment_content_repair_case(
        td,
        input_docx=source,
        plan_payload={
            "english_font_slot_repairs": [
                {
                    "scope": "all_ascii_runs",
                    "surface_allowlist": [{"contains_text": "allowed ASCII"}],
                }
            ]
        },
    )
    if proc.returncode != 0:
        return proc.returncode, (proc.stdout or "") + (proc.stderr or "")

    output = td / "comment-content-output.docx"
    ns = {"w": "http://schemas.openxmlformats.org/wordprocessingml/2006/main"}
    w = "{%s}" % ns["w"]
    with ZipFile(output) as zf:
        root = ET.fromstring(zf.read("word/document.xml"))
    changed = {"allowed": False, "blocked": False}
    for para in root.findall(".//w:p", ns):
        text = "".join(node.text or "" for node in para.findall(".//w:t", ns))
        if "allowed ASCII" not in text and "blocked ASCII" not in text:
            continue
        has_times = any(
            (fonts.get(w + "ascii") == "Times New Roman" or fonts.get(w + "hAnsi") == "Times New Roman")
            for fonts in para.findall(".//w:rFonts", ns)
        )
        changed["allowed" if "allowed ASCII" in text else "blocked"] = has_times
    ok = changed["allowed"] and not changed["blocked"]
    return (0 if ok else 1, json.dumps(changed, ensure_ascii=False))


