def case_gate_direct_body_text_excludes_toc_caption_valid(td: Path) -> tuple[int, str]:
    from xml.etree import ElementTree as ET
    from validate_skill_gate_record_evidence import _body_text_paragraphs, _docx_paragraph_text, _robust_body_text_paragraphs

    w_ns = "http://schemas.openxmlformats.org/wordprocessingml/2006/main"

    def add_p(body: ET.Element, text: str) -> None:
        paragraph = ET.SubElement(body, f"{{{w_ns}}}p")
        run = ET.SubElement(paragraph, f"{{{w_ns}}}r")
        node = ET.SubElement(run, f"{{{w_ns}}}t")
        node.text = text

    root = ET.Element(f"{{{w_ns}}}document")
    body = ET.SubElement(root, f"{{{w_ns}}}body")
    for text in (
        "目  录",
        "摘要I",
        "1  引言1",
        "参考文献39",
        "致谢42",
        "1  引言",
        "在当今数字化时代，校园安全已成为社会广泛关注的焦点问题。",
        "图2-1 YOLOv8-Pose 网络模型结构图",
        "表5-1  系统测试结果汇总",
        "随着计算机视觉和深度学习技术的发展，系统实现了视频抽帧与姿态检测。",
        "参考文献",
    ):
        add_p(body, text)

    body_texts = [_docx_paragraph_text(p) for p in _body_text_paragraphs(root)]
    robust_texts = [_docx_paragraph_text(p) for p in _robust_body_text_paragraphs(root)]
    forbidden = ("摘要I", "参考文献39", "致谢42", "图2-1", "表5-1")
    ok = (
        body_texts == robust_texts
        and len(body_texts) == 2
        and all(not text.startswith(forbidden) for text in body_texts)
    )
    return (0 if ok else 1), json.dumps({"body_texts": body_texts, "robust_texts": robust_texts}, ensure_ascii=False)


