    write_text(
        evidence,
        "\n".join(
            [
                "# Review Evidence",
                "- target identifier: references_entries",
                "- surface paragraph-and-typography verdict: fail typography drift: style, font",
                "- surface geometry verdict: pass",
            ]
        )
        + "\n",
    )
    status, verdict, reason = surface_inventory_row_state(evidence)
    text = f"status={status}\nverdict={verdict}\nreason={reason}\n"
    ok = status == "blocked" and verdict == "blocked"
    return (0 if ok else 1), text


