def write_valid_content_manifest(path: Path) -> None:
    payload = {
        "schema": "graduation-project-builder.thesis-content.v1",
        "title": "Scenic Spot Review Sentiment Analysis System",
        "zh_abstract": "本文围绕景区评论数据的采集、清洗、情感分类和结果展示展开，结合实际项目说明系统实现流程。",
        "zh_keywords": ["景区评论", "情感分析", "数据采集", "可视化"],
        "en_abstract": "This thesis studies the collection, cleaning, sentiment classification, and result presentation of scenic spot review data, and explains the implementation through the actual project workflow.",
        "en_keywords": ["scenic spots", "sentiment analysis", "review data", "visualization"],
        "chapters": [
            {
                "title": "1 Introduction",
                "paragraphs": [
                    "The project focuses on review data collection and sentiment analysis for scenic spot comments.",
                    "The system includes data preprocessing, classification, statistics, and visual presentation modules.",
                ],
                "sections": [
                    {
                        "title": "1.1 Research Background",
                        "paragraphs": ["Online reviews provide a direct data source for understanding visitor feedback and service quality."],
                    }
                ],
            },
            {
                "title": "2 System Design",
                "paragraphs": ["The design separates data ingestion, cleaning, analysis, and reporting into clear modules."],
            },
        ],
        "references": [
            "Pang B, Lee L. Opinion Mining and Sentiment Analysis[J]. Foundations and Trends in Information Retrieval, 2008, 2(1-2): 1-135.",
            "Liu B. Sentiment Analysis and Opinion Mining[M]. San Rafael: Morgan & Claypool Publishers, 2012.",
        ],
        "acknowledgements": "Thanks are given to the supervisor and classmates who supported the project implementation and thesis writing.",
    }
    write_text(path, json.dumps(payload, ensure_ascii=False, indent=2) + "\n")

def run_canonical_thesis_dry_run(td: Path, content_mutator=None, adapter_mutator=None) -> subprocess.CompletedProcess[str]:
    template = make_min_docx(td / "template.docx", ["摘要", "关键词", "Abstract", "Key Words:", "Contents", "1 Introduction"])
    adapter = td / "thesis-local-adapter.json"
    content = td / "thesis-content.json"
    write_valid_content_manifest(content)
    if content_mutator is not None:
        payload_data = json.loads(content.read_text(encoding="utf-8"))
        content_mutator(payload_data)
        write_text(content, json.dumps(payload_data, ensure_ascii=False, indent=2) + "\n")
    payload = {
        "schema": "graduation-project-builder.local-thesis-adapter.v1",
        "adapter_type": "run-manifest",
        "canonical_scripts": ["scripts/build_canonical_thesis.py"],
        "template_specific": True,
        "template_path": str(template),
        "template_fingerprint": file_sha256(template),
        "project_root": str(td),
        "run_root": str(td / "run"),
        "content_manifest": str(content),
        "output_docx": str(td / "out" / "thesis.docx"),
        "output_pdf": str(td / "out" / "thesis.pdf"),
        "allowed_scope": ["template path", "content manifest path", "output paths"],
    }
    if adapter_mutator is not None:
        adapter_mutator(payload)
    write_text(adapter, json.dumps(payload, ensure_ascii=False, indent=2) + "\n")
    builder = SKILL_ROOT / "scripts" / "build_canonical_thesis.py"
    return subprocess.run(
        [
            str(PYTHON_EXE),
            str(builder),
            "--adapter",
            str(adapter),
            "--dry-run-validate",
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(MEDIUM_SUBPROCESS_TIMEOUT),
    )


