def case_sample_self_check_figure_contract_uses_manifest_source_valid(td: Path) -> tuple[int, str]:
    import hashlib
    from sample_self_check import extract_figure_contract_checks

    def file_hash(path: Path) -> str:
        digest = hashlib.sha256()
        with path.open("rb") as handle:
            for chunk in iter(lambda: handle.read(65536), b""):
                digest.update(chunk)
        return digest.hexdigest()

    image = make_png(td / "runtime.png", 1200, 800)
    caption = "\u56fe5-1 \u7cfb\u7edf\u9996\u9875"
    source_docx = make_body_picture_docx(td / "manifest-source.docx", image, caption=caption, width_inches=1.0)
    final_docx = td / "manifest-final.docx"
    shutil.copyfile(source_docx, final_docx)
    manifest = runtime_figure_manifest(td, image)
    manifest["source_docx_path"] = str(source_docx)
    manifest["source_docx_sha256"] = file_hash(source_docx)
    manifest["final_docx_path"] = str(final_docx)
    manifest["final_docx_sha256"] = file_hash(final_docx)
    manifest_path = td / "figure-manifest.json"
    manifest_path.write_text(json.dumps(manifest, ensure_ascii=False, indent=2), encoding="utf-8")

    issues, summary, detectors = extract_figure_contract_checks(manifest_path, final_docx, None)
    ok = not issues and summary == "passed" and detectors and detectors[0].get("passed") is True
    return (
        0 if ok else 1,
        json.dumps({"summary": summary, "issues": issues, "detectors": detectors}, ensure_ascii=False),
    )


