def case_docx_apply_table_style_collision_valid(td: Path) -> tuple[int, str]:
    from lxml import etree as ET
    from docx_apply_table_family import NS, W, copy_missing_styles, w_attr

    target_styles = f'''<?xml version="1.0" encoding="UTF-8" standalone="no"?>
<w:styles xmlns:w="{NS["w"]}">
  <w:style w:type="table" w:styleId="af8"><w:name w:val="Target Table Grid"/><w:tblPr><w:tblBorders><w:top w:val="nil"/></w:tblBorders></w:tblPr></w:style>
  <w:style w:type="paragraph" w:styleId="a4"><w:name w:val="annotation text"/></w:style>
</w:styles>'''.encode("utf-8")
    template_styles = f'''<?xml version="1.0" encoding="UTF-8" standalone="no"?>
<w:styles xmlns:w="{NS["w"]}">
  <w:style w:type="table" w:styleId="a4" w:default="1"><w:name w:val="Normal Table"/><w:tblPr><w:tblCellMar><w:left w:w="108" w:type="dxa"/></w:tblCellMar></w:tblPr></w:style>
  <w:style w:type="table" w:styleId="af8"><w:name w:val="Table Grid"/><w:basedOn w:val="a4"/><w:tblPr><w:tblBorders><w:top w:val="single" w:sz="4"/></w:tblBorders></w:tblPr></w:style>
</w:styles>'''.encode("utf-8")
    target_members = {"word/styles.xml": target_styles}
    template_members = {"word/styles.xml": template_styles}
    copied, style_map, collisions = copy_missing_styles(target_members, template_members, {"af8"})
    styles = ET.fromstring(target_members["word/styles.xml"])
    cloned_af8 = styles.xpath('//w:style[@w:styleId="tplTbl_af8"]', namespaces=NS)
    cloned_a4 = styles.xpath('//w:style[@w:styleId="tplTbl_a4"]', namespaces=NS)
    based_on = cloned_af8[0].find("w:basedOn", NS) if cloned_af8 else None
    ok = (
        style_map.get("af8") == "tplTbl_af8"
        and style_map.get("a4") == "tplTbl_a4"
        and "tplTbl_af8" in copied
        and "tplTbl_a4" in copied
        and bool(cloned_af8)
        and bool(cloned_a4)
        and based_on is not None
        and based_on.get(w_attr("val")) == "tplTbl_a4"
        and collisions.get("af8", {}).get("mapped_style_id") == "tplTbl_af8"
    )
    return (
        0 if ok else 1,
        "table style collision cloned"
        if ok
        else json.dumps({"copied": copied, "style_map": style_map, "collisions": collisions}, ensure_ascii=False),
    )


