def case_update_static_toc_logical_page_valid(td: Path) -> tuple[int, str]:
    mapping = td / "heading-pages.json"
    write_text(
        mapping,
        json.dumps(
            [
                {"text": "1 Introduction", "page": 4, "level": 1},
                {"text": "2 Methods", "page": 5, "level": 1},
            ],
            ensure_ascii=False,
        ),
    )
    source = make_raw_docx(
        td / "toc-source.docx",
        '''
    <w:p><w:r><w:t>目录</w:t></w:r></w:p>
    <w:p><w:r><w:t>1 Introduction</w:t></w:r><w:r><w:tab/><w:t>1</w:t></w:r></w:p>
    <w:p><w:r><w:t>2 Methods</w:t></w:r><w:r><w:tab/><w:t>1</w:t></w:r></w:p>
    <w:p><w:pPr><w:pageBreakBefore/></w:pPr><w:r><w:t>1 Introduction</w:t></w:r></w:p>
    <w:p><w:pPr><w:pageBreakBefore/></w:pPr><w:r><w:t>2 Methods</w:t></w:r></w:p>
''',
    )
    output = td / "toc-output.docx"
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "update_static_toc.py"),
            "--input",
            str(source),
            "--mapping",
            str(mapping),
            "--output",
            str(output),
            "--reference-toc",
            str(source),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(120),
    )
    if proc.returncode != 0:
        return proc.returncode, proc.stdout + proc.stderr
    with zipfile.ZipFile(output) as zf:
        doc_xml = zf.read("word/document.xml").decode("utf-8", errors="replace")
    from xml.etree import ElementTree as ET

    ns = {"w": "http://schemas.openxmlformats.org/wordprocessingml/2006/main"}
    root = ET.fromstring(doc_xml)
    toc_text_runs = [
        [text_node.text or "" for text_node in paragraph.findall(".//w:t", ns)]
        for paragraph in root.findall(".//w:p", ns)
    ]
    ok = any("1 Introduction" in "".join(runs) and len(runs) > 1 and runs[-1] == "1" for runs in toc_text_runs) and any(
        "2 Methods" in "".join(runs) and len(runs) > 1 and runs[-1] == "2" for runs in toc_text_runs
    )
    return (0 if ok else 1, "TOC logical page updated" if ok else doc_xml)


