def case_update_static_toc_frontmatter_level1_ignored_valid(td: Path) -> tuple[int, str]:
    mapping = td / "heading-pages.json"
    write_text(
        mapping,
        json.dumps(
            [
                {"text": "ABSTRACT", "page": 7, "level": 1},
                {"text": "\u7b2c1\u7ae0 \u7eea\u8bba", "page": 11, "level": 1},
                {"text": "1.1 \u7814\u7a76\u80cc\u666f\u4e0e\u610f\u4e49", "page": 11, "level": 2},
                {"text": "\u53c2\u8003\u6587\u732e", "page": 23, "level": 1},
                {"text": "\u81f4\u3000\u3000\u8c22", "page": 24, "level": 1},
            ],
            ensure_ascii=False,
        ),
    )
    source = make_raw_docx(
        td / "toc-frontmatter-source.docx",
        '''
    <w:p><w:r><w:t>\u76ee\u5f55</w:t></w:r></w:p>
    <w:p><w:r><w:t>\u7b2c1\u7ae0 \u7eea\u8bba</w:t></w:r><w:r><w:tab/><w:t>5</w:t></w:r></w:p>
    <w:p><w:r><w:t>1.1 \u7814\u7a76\u80cc\u666f\u4e0e\u610f\u4e49</w:t></w:r><w:r><w:tab/><w:t>5</w:t></w:r></w:p>
    <w:p><w:r><w:t>\u53c2\u8003\u6587\u732e</w:t></w:r><w:r><w:tab/><w:t>17</w:t></w:r></w:p>
    <w:p><w:r><w:t>\u81f4\u3000\u3000\u8c22</w:t></w:r><w:r><w:tab/><w:t>18</w:t></w:r></w:p>
    <w:p><w:pPr><w:pageBreakBefore/></w:pPr><w:r><w:t>\u7b2c1\u7ae0 \u7eea\u8bba</w:t></w:r></w:p>
''',
    )
    output = td / "toc-frontmatter-output.docx"
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "update_static_toc.py"),
            "--input",
            str(source),
            "--mapping",
            str(mapping),
            "--output",
            str(output),
            "--reference-toc",
            str(source),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(120),
    )
    if proc.returncode != 0:
        return proc.returncode, proc.stdout + proc.stderr
    from docx import Document

    paragraphs = [paragraph.text for paragraph in Document(str(output)).paragraphs]
    toc_start = next((idx for idx, text in enumerate(paragraphs) if text.strip() == "\u76ee\u5f55"), -1)
    toc_entries = []
    for text in paragraphs[toc_start + 1 :]:
        if "\t" not in text:
            break
        toc_entries.append(text)
    ok = (
        toc_entries[0].endswith("\t1")
        and toc_entries[1].endswith("\t1")
        and toc_entries[2].endswith("\t13")
        and toc_entries[3].endswith("\t14")
        and not any(entry.endswith("\t5") or entry.endswith("\t17") or entry.endswith("\t18") for entry in toc_entries)
    )
    return (
        0 if ok else 1,
        "TOC logical body page start ignores front-matter level-1 rows" if ok else json.dumps(toc_entries, ensure_ascii=False),
    )


