def make_reference_residue_repair_docx(path: Path) -> Path:
    path.parent.mkdir(parents=True, exist_ok=True)

    def citation_run(number: int) -> str:
        return (
            f'<w:hyperlink w:anchor="cite_ref_{number}">'
            f'<w:r><w:rPr><w:vertAlign w:val="superscript"/></w:rPr><w:t>[{number}]</w:t></w:r>'
            f"</w:hyperlink>"
        )

    content_types = """<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
  <Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
  <Default Extension="xml" ContentType="application/xml"/>
  <Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>
  <Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/>
</Types>
"""
    rels = """<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/>
</Relationships>
"""
    styles_xml = """<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:style w:type="paragraph" w:styleId="Normal"><w:name w:val="Normal"/></w:style>
</w:styles>
"""
    residue_prefix = "为补足参考文献来源并保持正文引用顺序，本文在相关方法说明中补充如下文献依据："
    document_xml = f"""<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:body>
    <w:p><w:r><w:t>3.2 五类异常行为规则设计</w:t></w:r></w:p>
    <w:p><w:r><w:t>规则设计先承接已有姿态识别研究</w:t></w:r>{citation_run(11)}<w:r><w:t>。</w:t></w:r></w:p>
    <w:p><w:r><w:t>普通正文段落应保留在原位置。</w:t></w:r></w:p>
    <w:p><w:r><w:t>{residue_prefix}</w:t></w:r><w:r><w:t>Faster R-CNN 说明两阶段检测仍是重要基线</w:t></w:r>{citation_run(12)}<w:r><w:t>。</w:t></w:r><w:r><w:t>Mask R-CNN 证明实例分割与目标定位可以形成统一框架</w:t></w:r>{citation_run(13)}<w:r><w:t>。</w:t></w:r></w:p>
    <w:p><w:r><w:t>参考文献</w:t></w:r></w:p>
    <w:p><w:r><w:t>[1] Reference Item 1[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[2] Reference Item 2[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[3] Reference Item 3[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[4] Reference Item 4[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[5] Reference Item 5[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[6] Reference Item 6[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[7] Reference Item 7[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[8] Reference Item 8[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[9] Reference Item 9[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[10] Reference Item 10[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[11] Reference Item 11[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[12] Reference Item 12[J].</w:t></w:r></w:p>
    <w:p><w:r><w:t>[13] Reference Item 13[J].</w:t></w:r></w:p>
    <w:sectPr/>
  </w:body>
</w:document>
"""
    with zipfile.ZipFile(path, "w", zipfile.ZIP_DEFLATED) as zf:
        zf.writestr("[Content_Types].xml", content_types)
        zf.writestr("_rels/.rels", rels)
        zf.writestr("word/document.xml", document_xml)
        zf.writestr("word/styles.xml", styles_xml)
    return path


def case_repair_frontmatter_toc_structure_preserves_frontmatter_valid(td: Path) -> tuple[int, str]:
    source = make_frontmatter_toc_repair_docx(td / "source.docx")
    output = td / "output.docx"
    report = td / "report.json"
    proc = run_frontmatter_toc_repair(
        source,
        output,
        report,
        "toc-contamination,abstract-style,heading1-baseline",
    )
    if proc.returncode != 0:
        return proc.returncode, proc.stdout + proc.stderr
    payload = json.loads(report.read_text(encoding="utf-8"))
    with zipfile.ZipFile(output, "r") as zf:
        document_xml = zf.read("word/document.xml").decode("utf-8", errors="replace")
        styles_xml = zf.read("word/styles.xml").decode("utf-8", errors="replace")
    removed = payload["changes"]["toc_contamination_removed"]
    removed_text = "\n".join(item.get("text", "") for item in removed)
    ok = (
        payload["schema"] == "graduation-project-builder.thesis-frontmatter-toc-structure-repair.v1"
        and payload["changed_zip_parts"] == ["word/document.xml", "word/styles.xml"]
        and payload["input_sha256"]
        and payload["output_sha256"]
        and len(removed) == 2
        and "表5-1" in removed_text
        and "文献类型" in removed_text
        and "计算机系2026" in document_xml
        and "本文摘要内容" in document_xml
        and "关键词" in document_xml
        and "表5-1" not in document_xml
        and "文献类型" not in document_xml
        and 'w:styleId="Style17"' in styles_xml
        and 'w:pStyle w:val="Heading1"' in document_xml
        and "pageBreakBefore" in document_xml
    )
    if ok:
        return 0, "frontmatter TOC structure repair preserved front matter and chapter page break"
    return 1, json.dumps({"removed": removed, "document": document_xml, "styles": styles_xml}, ensure_ascii=False)


