def case_repair_frontmatter_toc_structure_reference_residue_preserves_citations_valid(td: Path) -> tuple[int, str]:
    source = make_reference_residue_repair_docx(td / "source.docx")
    output = td / "output.docx"
    report = td / "report.json"
    proc = run_frontmatter_toc_repair(source, output, report, "reference-residue")
    if proc.returncode != 0:
        return proc.returncode, proc.stdout + proc.stderr
    payload = json.loads(report.read_text(encoding="utf-8"))
    with zipfile.ZipFile(output, "r") as zf:
        document_xml = zf.read("word/document.xml").decode("utf-8", errors="replace")
    source_citations = collect_citation_snapshot(source)
    final_citations = collect_citation_snapshot(output)
    _, citation_issues = build_citation_diff_report(source_citations, final_citations)
    changes = payload["changes"]["reference_supplement_residue_repaired"]
    ok = (
        payload["changed_zip_parts"] == ["word/document.xml"]
        and changes
        and changes[0]["citation_numbers_preserved"] == [12, 13]
        and "为补足参考文献来源并保持正文引用顺序" not in document_xml
        and "相关研究可以进一步归纳为以下几类" in document_xml
        and "[12]" in document_xml
        and "[13]" in document_xml
        and not citation_issues
    )
    if ok:
        return 0, "reference residue repaired while preserving source citation runs"
    return 1, json.dumps({"changes": changes, "citation_issues": citation_issues, "document": document_xml}, ensure_ascii=False)


def case_repair_thesis_closeout_format_redundant_chapter_breaks_valid(td: Path) -> tuple[int, str]:
    from repair_thesis_closeout_format import paragraph_text, repair_document

    document_xml = """<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:body>
    <w:p><w:r><w:t>目录</w:t></w:r></w:p>
    <w:p><w:pPr><w:pStyle w:val="TOC1"/></w:pPr><w:r><w:t>1  引言</w:t></w:r><w:r><w:tab/><w:t>1</w:t></w:r></w:p>
    <w:p><w:pPr><w:pageBreakBefore/></w:pPr><w:r><w:t>1  引言</w:t></w:r></w:p>
    <w:p><w:r><w:t>引言部分正文。</w:t></w:r></w:p>
    <w:p><w:pPr><w:pageBreakBefore/></w:pPr><w:r><w:br w:type="page"/></w:r><w:r><w:t>2  相关理论</w:t></w:r></w:p>
    <w:p><w:r><w:t>理论部分正文。</w:t></w:r></w:p>
    <w:p/>
    <w:p/>
    <w:p><w:pPr><w:pageBreakBefore/></w:pPr><w:r><w:t>3  方法设计</w:t></w:r></w:p>
    <w:p><w:r><w:t>方法部分正文。</w:t></w:r></w:p>
    <w:sectPr/>
  </w:body>
</w:document>
"""
    ns = {"w": "http://schemas.openxmlformats.org/wordprocessingml/2006/main"}
    root = ET.fromstring(document_xml)
    changes = repair_document(root, {"chapter-page-starts"})
    paragraphs = root.findall("./w:body/w:p", ns)
    paragraph_texts = [paragraph_text(paragraph).strip() for paragraph in paragraphs]
    chapter2 = next(paragraph for paragraph in paragraphs if paragraph_text(paragraph).strip().startswith("2  "))
    chapter3_index = paragraph_texts.index("3  方法设计")
    preceding_text = paragraph_texts[chapter3_index - 1]
    serialized = ET.tostring(root, encoding="unicode")
    ok = (
        not chapter2.findall(".//w:br", ns)
        and preceding_text == "理论部分正文。"
        and len(changes["chapter_inline_page_breaks_removed"]) == 1
        and len(changes["chapter_preceding_blank_paragraphs_removed"]) == 2
        and serialized.count("pageBreakBefore") == 3
    )
    if ok:
        return 0, "redundant chapter page-break residue removed"
    return 1, json.dumps({"changes": changes, "paragraphs": paragraph_texts, "document": serialized}, ensure_ascii=False)


def case_repair_frontmatter_toc_structure_chapter_heading_duplicate_page_break_valid(td: Path) -> tuple[int, str]:
    source = make_frontmatter_toc_repair_docx(td / "chapter-duplicate-page-break-source.docx")
    with zipfile.ZipFile(source, "r") as zf:
        parts = {name: zf.read(name) for name in zf.namelist()}
    document_xml = """<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:body>
    <w:p><w:r><w:t>\u76ee\u5f55</w:t></w:r></w:p>
    <w:p><w:pPr><w:pStyle w:val="TOC1"/></w:pPr><w:r><w:t>1 \u5f15\u8a00</w:t></w:r><w:r><w:tab/><w:t>1</w:t></w:r></w:p>
    <w:p><w:pPr><w:pageBreakBefore/></w:pPr><w:r><w:br w:type="page"/></w:r><w:r><w:t>1 \u5f15\u8a00</w:t></w:r></w:p>
    <w:p><w:r><w:t>\u6b63\u6587\u3002</w:t></w:r></w:p>
    <w:p><w:pPr><w:pageBreakBefore/></w:pPr><w:r><w:br w:type="page"/></w:r><w:r><w:t>2 \u76f8\u5173\u7406\u8bba</w:t></w:r></w:p>
    <w:p><w:r><w:t>\u7b2c\u4e8c\u7ae0\u6b63\u6587\u3002</w:t></w:r></w:p>
    <w:sectPr/>
  </w:body>
</w:document>
"""
    parts["word/document.xml"] = document_xml.encode("utf-8")
    with zipfile.ZipFile(source, "w", zipfile.ZIP_DEFLATED) as zf:
        for name, data in parts.items():
            zf.writestr(name, data)
    output = td / "chapter-duplicate-page-break-output.docx"
    report = td / "chapter-duplicate-page-break-report.json"
    proc = run_frontmatter_toc_repair(source, output, report, "duplicate-page-breaks")
    if proc.returncode != 0:
        return proc.returncode, proc.stdout + proc.stderr
    payload = json.loads(report.read_text(encoding="utf-8"))
    with zipfile.ZipFile(output, "r") as zf:
        document_xml = zf.read("word/document.xml").decode("utf-8", errors="replace")
    removed = payload["changes"]["duplicate_page_breaks_removed"]
    ok = (
        payload["changed_zip_parts"] == ["word/document.xml"]
        and len(removed) == 2
        and all(item.get("reason") == "level-1 body heading already has pageBreakBefore" for item in removed)
        and '<w:br w:type="page"' not in document_xml
        and document_xml.count("pageBreakBefore") == 2
        and "2 \u76f8\u5173\u7406\u8bba" in document_xml
    )
    return (0 if ok else 1, json.dumps({"removed": removed, "document": document_xml}, ensure_ascii=False))


