def case_update_static_toc_run_rpr_baseline_valid(td: Path) -> tuple[int, str]:
    mapping = td / "heading-pages.json"
    write_text(
        mapping,
        json.dumps(
            [
                {"text": "1 Introduction", "page": 4, "level": 1},
                {"text": "1.1 Background", "page": 5, "level": 2},
                {"text": "1.1.1 Data Source", "page": 6, "level": 3},
            ],
            ensure_ascii=False,
        ),
    )
    reference = make_toc_metric_docx(td / "toc-rpr-reference.docx")
    source = make_toc_metric_docx(td / "toc-rpr-source.docx", variant="run_rpr_missing")
    output = td / "toc-rpr-output.docx"
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "update_static_toc.py"),
            "--input",
            str(source),
            "--mapping",
            str(mapping),
            "--output",
            str(output),
            "--reference-toc",
            str(reference),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(120),
    )
    if proc.returncode != 0:
        return proc.returncode, proc.stdout + proc.stderr
    with zipfile.ZipFile(output) as zf:
        doc_xml = zf.read("word/document.xml").decode("utf-8", errors="replace")
    from xml.etree import ElementTree as ET

    ns = {"w": "http://schemas.openxmlformats.org/wordprocessingml/2006/main"}
    root = ET.fromstring(doc_xml)
    toc_runs = [
        run
        for paragraph in root.findall(".//w:p", ns)
        if (
            (paragraph.find("w:pPr/w:pStyle", ns) is not None)
            and paragraph.find("w:pPr/w:pStyle", ns).attrib.get("{http://schemas.openxmlformats.org/wordprocessingml/2006/main}val")
            in {"TOC1", "TOC2", "TOC3"}
        )
        for run in paragraph.findall("w:r", ns)
    ]
    missing_direct_rpr = any(run.find("w:rPr", ns) is None for run in toc_runs)
    toc_run_count = len(toc_runs)
    toc_rpr_count = sum(1 for run in toc_runs if run.find("w:rPr", ns) is not None)
    toc_simsun_count = sum(
        1
        for run in toc_runs
        if run.find("w:rPr/w:rFonts", ns) is not None
        and run.find("w:rPr/w:rFonts", ns).attrib.get("{http://schemas.openxmlformats.org/wordprocessingml/2006/main}eastAsia")
        == "SimSun"
    )
    toc_szcs_24_count = sum(
        1
        for run in toc_runs
        if run.find("w:rPr/w:szCs", ns) is not None
        and run.find("w:rPr/w:szCs", ns).attrib.get("{http://schemas.openxmlformats.org/wordprocessingml/2006/main}val")
        == "24"
    )
    ok = (
        not missing_direct_rpr
        and toc_run_count == 9
        and toc_rpr_count == 9
        and toc_simsun_count == 9
        and toc_szcs_24_count == 9
    )
    return (0 if ok else 1, "TOC run rPr restored from reference baseline" if ok else doc_xml)


