def case_sample_self_check_abstract_requirement_profile_donor_valid(td: Path) -> tuple[int, str]:
    from sample_self_check import (
        ABSTRACT_BASELINE_PROFILE_SCHEMA,
        collect_abstract_surface_signatures,
        extract_abstract_baseline_checks,
    )

    reference = make_raw_docx(td / "abstract-format-requirements.docx", '<w:p><w:r><w:t>format requirements only</w:t></w:r></w:p>')
    donor_xml = '''
    <w:p><w:r><w:t>\u6458 \u8981</w:t></w:r></w:p>
    <w:p><w:r><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman"/><w:sz w:val="24"/></w:rPr><w:t>\u57fa\u7ebf\u6458\u8981\u6b63\u6587 YOLO\u3002</w:t></w:r></w:p>
    <w:p><w:r><w:rPr><w:b/><w:sz w:val="24"/></w:rPr><w:t>\u5173\u952e\u8bcd:</w:t></w:r><w:r><w:rPr><w:sz w:val="24"/></w:rPr><w:t>\u65c5\u6e38; \u8bc4\u8bba; \u60c5\u611f</w:t></w:r></w:p>
    <w:p><w:r><w:t>Abstract</w:t></w:r></w:p>
    <w:p><w:r><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman"/><w:sz w:val="24"/></w:rPr><w:t>Baseline English abstract body text.</w:t></w:r></w:p>
    <w:p><w:r><w:rPr><w:b/><w:sz w:val="24"/></w:rPr><w:t>Key words:</w:t></w:r><w:r><w:rPr><w:sz w:val="24"/></w:rPr><w:t>tourism; sentiment</w:t></w:r></w:p>
    <w:p><w:r><w:t>1 Introduction</w:t></w:r></w:p>
'''
    donor = make_raw_docx(td / "approved-abstract-profile-source.docx", donor_xml)
    final_xml = donor_xml.replace("\u57fa\u7ebf\u6458\u8981\u6b63\u6587", "\u4e2d\u6587\u6458\u8981\u6b63\u6587").replace("Baseline English abstract body text.", "English abstract body text.")
    final = make_raw_docx(td / "abstract-profile-final.docx", final_xml)
    donor_surfaces = collect_abstract_surface_signatures(donor)
    profile_surfaces: dict[str, dict[str, object]] = {}
    for surface, row in donor_surfaces.items():
        profile_surfaces[surface] = {
            "text": row.get("text", ""),
            "style_name": row.get("style_name", ""),
            "signature": row.get("signature", {}),
            "run_signature": row.get("run_signature", {}),
        }
    profile = td / "abstract-baseline-profile.json"
    write_text(
        profile,
        json.dumps(
            {
                "schema": ABSTRACT_BASELINE_PROFILE_SCHEMA,
                "source_type": "official-format-requirements",
                "source_docx_path": str(donor),
                "source_docx_sha256": file_sha256(donor),
                "surfaces": profile_surfaces,
            },
            ensure_ascii=False,
            indent=2,
        )
        + "\n",
    )
    issues, summary = extract_abstract_baseline_checks(reference, final, profile)
    ok = not issues
    return (0 if ok else 1, summary + "\n" + "\n".join(issues))


