def case_pagination_raw_unexpected_near_empty_rejected(td: Path) -> tuple[int, str]:
    from validate_skill_gate_record_evidence import _validate_whole_document_pagination_fields

    reviewed_output = make_dummy_file(td / "reviewed.docx")
    structure_path = td / "whole-pagination.json"
    blank_scan = (
        "pass rendered blank/near-empty page scan template_blank_pages=[] actual_blank_pages=[] "
        "unexpected_blank_pages=[] template_near_empty_pages=[] actual_near_empty_pages=[8] "
        "unexpected_near_empty_pages=[] raw_unexpected_near_empty_pages=[8] "
        "allowed_content_growth_near_empty_pages=[8] rendered_ink_ratio template_min=0.01 actual_min=0.001 "
        "section page field TOC logical physical chapter tail"
    )
    payload = {
        "schema": "graduation-project-builder.docx-pagination-structure.v1",
        "generator_script": "inspect_docx_pagination_structure.py",
        "final_docx_path": str(reviewed_output),
        "final_docx_sha256": file_sha256(reviewed_output),
        "fatal_differences": [],
        "section_count_verdict": "pass",
        "header_footer_reference_verdict": "pass",
        "page_number_restart_verdict": "pass",
        "blank_near_empty_page_scan_verdict": blank_scan,
        "tail_block_opener_page_map": (
            "pass tail block rendered map: references previous content physical page=7; "
            "references physical page=8; acknowledgement physical page=9; "
            "references_page_found=yes; references_fresh_page_verdict=pass; "
            "references_prior_block_separation_verdict=pass; "
            "references_opener_owner_evidence=sample_self_check detector tail-block.pagination-contract passed"
        ),
    }
    write_text(structure_path, json.dumps(payload, ensure_ascii=False, indent=2) + "\n")
    values = {
        "- DOCX pagination structure schema:": "graduation-project-builder.docx-pagination-structure.v1",
        "- DOCX pagination structure generator:": "inspect_docx_pagination_structure.py",
        "- DOCX pagination structure evidence path:": str(structure_path),
        "- DOCX pagination structure verdict:": "pass",
        "- fatal pagination topology differences:": "[]",
        "- allowed content-growth pagination differences:": "[]",
        "- all pagination topology differences:": "[]",
        "- section count verdict:": "pass",
        "- header/footer reference verdict:": "pass",
        "- page-number restart verdict:": "pass",
        "- whole-document pagination verdict:": "pass section page field TOC logical physical chapter tail evidence verified",
    }
    raw_values = {
        "- reviewed output path:": str(reviewed_output),
        "- DOCX pagination structure evidence path:": str(structure_path),
        "- blank/near-empty page scan verdict:": blank_scan,
        "- rendered page count baseline/actual:": "template pages=10; actual pages=10",
        "- section count baseline/actual:": "template section count=3; actual section count=3",
        "- section boundary map baseline/actual:": "template section page=1; actual section page=1",
        "- page-number format/restart map baseline/actual:": "template page restart=1; actual page restart=1",
    }
    for prefix in (
        "- package baseline manifest path:",
        "- package drift report path:",
        "- package drift verdict:",
        "- pre-mutation page map path:",
        "- post-mutation page map path:",
        "- whole-document pagination diff path:",
        "- header/footer reference map baseline/actual:",
        "- header/footer link-to-previous inferred map baseline/actual:",
        "- section property map baseline/actual:",
        "- header/footer link-to-previous map baseline/actual:",
        "- hard page-break / section-break map baseline/actual:",
        "- field-refresh before/after state:",
        "- TOC-to-heading page sync map:",
        "- logical-to-physical page map:",
        "- chapter opener page map:",
        "- page-class occupancy rhythm verdict:",
        "- whole-document pagination verdict:",
    ):
        raw_values.setdefault(prefix, "section page field TOC logical physical chapter tail evidence 1")
    raw_values["- tail-block opener page map:"] = str(payload["tail_block_opener_page_map"])
    raw_values.update(values)
    issues = _validate_whole_document_pagination_fields(values, raw_values, td / "evidence.md", "whole_document_pagination")
    ok = any("unapproved raw unexpected near-empty pages" in issue for issue in issues)
    return (0 if ok else 1, "\n".join(issues))


