def case_repair_bibliography_entry_format_valid(td: Path) -> tuple[int, str]:
    reference_heading = escape("\u53c2\u8003\u6587\u732e")
    reference = make_bibliography_split_latin_docx(td / "repair-reference.docx", good=True)
    source = make_raw_docx(
        td / "repair-collapsed-source.docx",
        f'''
    <w:p><w:r><w:t>1 Introduction</w:t></w:r></w:p>
    <w:p><w:r><w:t>{reference_heading}</w:t></w:r></w:p>
    <w:p>
      <w:pPr><w:spacing w:line="320" w:lineRule="exact"/></w:pPr>
      <w:bookmarkStart w:id="1" w:name="cite_ref_1"/>
      <w:r><w:rPr><w:sz w:val="24"/></w:rPr><w:t>[1] Example Author. Example Title[J]. Journal, 2026.</w:t></w:r>
      <w:bookmarkEnd w:id="1"/>
    </w:p>
    <w:p><w:r><w:t>Acknowledgements</w:t></w:r></w:p>
''',
    )
    repaired = td / "repair-output.docx"
    repair_report = td / "repair-report.json"
    repair_proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(BIBLIOGRAPHY_REPAIR_SCRIPT),
            "--source-docx",
            str(source),
            "--template-docx",
            str(reference),
            "--output-docx",
            str(repaired),
            "--report",
            str(repair_report),
        ],
        cwd=str(SKILL_ROOT),
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )
    audit_proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(FONT_AUDIT_SCRIPT),
            str(repaired),
            "--reference-docx",
            str(reference),
        ],
        cwd=str(SKILL_ROOT),
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )
    output = (repair_proc.stdout or "") + (audit_proc.stdout or "")
    if repair_proc.returncode != 0 or audit_proc.returncode != 0:
        return 1, output
    report = json.loads(repair_report.read_text(encoding="utf-8"))
    first_entry = report["entries"][0]
    ok = (
        report["changed_zip_parts"] == ["word/document.xml"]
        and report["entry_count"] == 1
        and first_entry["run_count_after"] > 1
        and first_entry["bookmark_names"] == ["cite_ref_1"]
        and "bibliography font-slot checks: pass" in audit_proc.stdout
    )
    return (0 if ok else 1, output + json.dumps(report, ensure_ascii=False))


