def case_repair_thesis_reference_content_exact_valid(td: Path) -> tuple[int, str]:
    source = make_raw_docx(
        td / "reference-content-source.docx",
        '''
    <w:p><w:r><w:t>Old survey evidence supports the anomaly risk scoring path</w:t></w:r><w:r><w:t>[25]</w:t></w:r><w:r><w:t>.</w:t></w:r></w:p>
    <w:p><w:r><w:t>References</w:t></w:r></w:p>
    <w:p><w:bookmarkStart w:id="25" w:name="cite_ref_25"/><w:r><w:t>[25] Old A, Paper B. Anomaly detection: A survey[J]. Journal, 2009.</w:t></w:r><w:bookmarkEnd w:id="25"/></w:p>
''',
    )
    body_new = "A 2026 skeleton action-recognition study supports the posture-sequence basis of this anomaly review path"
    reference_new = "[25] Yan X, Zhang J, Xu W, Cao L, Liu W, Jiao Y. SkelFormer: Transformer-based skeleton action recognition for video sequences[J]. PLoS One, 2026, 21(4): e0340390."
    plan = td / "reference-content-plan.json"
    plan.write_text(
        json.dumps(
            {
                "schema": "graduation-project-builder.reference-content-repair.v1",
                "replacements": [
                    {
                        "name": "body_host_sentence",
                        "old": "Old survey evidence supports the anomaly risk scoring path",
                        "new": body_new,
                        "expected_count": 1,
                        "required_new_contains": ["2026"],
                    },
                    {
                        "name": "bibliography_entry_25",
                        "old": "[25] Old A, Paper B. Anomaly detection: A survey[J]. Journal, 2009.",
                        "new": reference_new,
                        "expected_count": 1,
                        "required_new_contains": ["2026", "[25]"],
                    },
                ],
                "final_must_contain": [body_new, reference_new],
            },
            ensure_ascii=False,
            indent=2,
        )
        + "\n",
        encoding="utf-8",
    )
    output_docx = td / "reference-content-output.docx"
    report_path = td / "reference-content-report.json"
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(REFERENCE_CONTENT_REPAIR_SCRIPT),
            "--input-docx",
            str(source),
            "--output-docx",
            str(output_docx),
            "--plan",
            str(plan),
            "--report-output",
            str(report_path),
        ],
        cwd=str(SKILL_ROOT),
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )
    if proc.returncode != 0:
        return proc.returncode, proc.stdout
    report = json.loads(report_path.read_text(encoding="utf-8"))
    with zipfile.ZipFile(output_docx, "r") as zf:
        document_xml = zf.read("word/document.xml").decode("utf-8")
    ok = (
        report["verdict"] == "pass"
        and report["package_scope"]["changed_parts"] == ["word/document.xml"]
        and report["package_scope"]["only_document_xml_changed"] is True
        and len(report["replacements"]) == 2
        and body_new in document_xml
        and reference_new in document_xml
        and "Old survey evidence" not in document_xml
        and "Journal, 2009" not in document_xml
    )
    return (0 if ok else 1, proc.stdout + json.dumps(report, ensure_ascii=False))


def make_caption_repair_fixture_docx(path: Path, body_xml: str, styles_xml: str | None = None) -> Path:
    path.parent.mkdir(parents=True, exist_ok=True)
    content_types = """<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
  <Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
  <Default Extension="xml" ContentType="application/xml"/>
  <Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>
  <Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/>
</Types>
"""
    rels = """<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
  <Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/>
</Relationships>
"""
    if styles_xml is None:
        styles_xml = """<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:style w:type="paragraph" w:styleId="Normal"><w:name w:val="Normal"/></w:style>
</w:styles>
"""
    document_xml = f'''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:body>
{body_xml}
    <w:sectPr/>
  </w:body>
</w:document>'''
    with zipfile.ZipFile(path, "w", zipfile.ZIP_DEFLATED) as zf:
        zf.writestr("[Content_Types].xml", content_types)
        zf.writestr("_rels/.rels", rels)
        zf.writestr("word/document.xml", document_xml)
        zf.writestr("word/styles.xml", styles_xml)
    return path


