def case_sample_self_check_cover_year_digits_valid(td: Path) -> tuple[int, str]:
    from sample_self_check import extract_cover_baseline_checks

    def make_cover_docx(path: Path, line: str) -> Path:
        return make_raw_docx(
            path,
            f'''
    <w:p><w:r><w:rPr><w:rFonts w:eastAsia="STZhongsong" w:ascii="STZhongsong" w:hAnsi="STZhongsong"/><w:b/><w:sz w:val="36"/></w:rPr><w:t>{escape(line)}</w:t></w:r></w:p>
    <w:p><w:r><w:t>\u6458\u8981</w:t></w:r></w:p>
''',
        )

    reference = make_cover_docx(
        td / "cover-year-reference.docx",
        "\u8ba1\u7b97\u673a\u7cfb\u672c\u79d1\u6bd5\u4e1a\u8bba\u6587\uff08\u8bbe\u8ba1\uff09",
    )
    valid = make_cover_docx(
        td / "cover-year-valid.docx",
        "\u8ba1\u7b97\u673a\u7cfb2026 \u5c4a\u672c\u79d1\u6bd5\u4e1a\u8bba\u6587\uff08\u8bbe\u8ba1\uff09",
    )
    invalid = make_cover_docx(
        td / "cover-year-invalid.docx",
        "\u8ba1\u7b97\u673a\u7cfbV2\u5c4a\u672c\u79d1\u6bd5\u4e1a\u8bba\u6587\uff08\u8bbe\u8ba1\uff09",
    )
    valid_issues, valid_summary = extract_cover_baseline_checks(reference, valid)
    invalid_issues, invalid_summary = extract_cover_baseline_checks(reference, invalid)
    invalid_text = "\n".join(invalid_issues)
    ok = (
        not valid_issues
        and valid_summary != "failed"
        and bool(invalid_issues)
        and ("latinRunPresent" in invalid_text or "latin_" in invalid_text)
    )
    detail = (
        f"valid_summary={valid_summary}; valid_issues={valid_issues}; "
        f"invalid_summary={invalid_summary}; invalid_issues={invalid_issues}"
    )
    return (0 if ok else 1, "cover year digits accepted; latin letters rejected\n" + detail)


