def case_template_profile_cover_title_same_page_rejected(td: Path) -> tuple[int, str]:
    from docx import Document
    from sample_self_check import extract_template_profile_front_matter_checks
    from thesis_template_profile import SCHEMA as TEMPLATE_PROFILE_SCHEMA

    profile = {
        "schema": TEMPLATE_PROFILE_SCHEMA,
        "markers": {
            "cover_zh_title": {"text": "农田碳汇数据可视化系统的设计与实现", "paragraph_indices": [0]},
            "cover_en_title": {"text": "Design and Implementation of Farmland Carbon Sink Data Visualization System", "paragraph_indices": [1]},
        },
        "front_matter": {
            "same_page_groups": [
                {"id": "cover-title-block", "members": ["cover_zh_title", "cover_en_title"], "source": "selftest"}
            ],
            "separated_page_pairs": [],
            "critical_surfaces": ["cover_zh_title", "cover_en_title"],
        },
    }
    profile_path = td / "template-profile.json"
    write_text(profile_path, json.dumps(profile, ensure_ascii=False, indent=2) + "\n")
    doc = Document()
    doc.add_paragraph("农田碳汇数据可视化系统的设计与实现")
    doc.add_paragraph("Design and Implementation of Farmland Carbon Sink Data Visualization System")
    doc.add_paragraph("Student Name")
    doc.add_paragraph("Supervisor Name")
