def add_svg_primary_fallback_to_docx(docx_path: Path, svg_path: Path) -> dict[str, str]:
    from xml.etree import ElementTree as ET

    rel_ns = "http://schemas.openxmlformats.org/package/2006/relationships"
    r_ns = "http://schemas.openxmlformats.org/officeDocument/2006/relationships"
    a_ns = "http://schemas.openxmlformats.org/drawingml/2006/main"
    asvg_ns = "http://schemas.microsoft.com/office/drawing/2016/SVG/main"
    ct_ns = "http://schemas.openxmlformats.org/package/2006/content-types"
    svg_ext_uri = "{96DAC541-7B7A-43D3-8B79-37D633B846F1}"

    tmp = docx_path.with_suffix(".svg-primary.tmp.docx")
    with zipfile.ZipFile(docx_path, "r") as zin:
        rel_root = ET.fromstring(zin.read("word/_rels/document.xml.rels"))
        doc_root = ET.fromstring(zin.read("word/document.xml"))
        content_root = ET.fromstring(zin.read("[Content_Types].xml"))
        image_rels = [
            rel for rel in rel_root.findall(f"{{{rel_ns}}}Relationship")
            if rel.attrib.get("Type", "").endswith("/image")
        ]
        png_rel = next((rel for rel in image_rels if rel.attrib.get("Target", "").lower().endswith(".png")), None)
        if png_rel is None:
            raise AssertionError("fixture DOCX has no PNG image relationship")
        existing_ids = {rel.attrib.get("Id", "") for rel in rel_root.findall(f"{{{rel_ns}}}Relationship")}
        numeric_ids = [int(rid[3:]) for rid in existing_ids if rid.startswith("rId") and rid[3:].isdigit()]
        svg_rid = f"rId{max(numeric_ids or [0]) + 1}"
        while svg_rid in existing_ids:
            svg_rid = f"rId{int(svg_rid[3:]) + 1}"
        svg_target = f"media/{svg_path.name}"
        svg_rel = ET.Element(f"{{{rel_ns}}}Relationship")
        svg_rel.attrib["Id"] = svg_rid
        svg_rel.attrib["Type"] = "http://schemas.openxmlformats.org/officeDocument/2006/relationships/image"
        svg_rel.attrib["Target"] = svg_target
        rel_root.append(svg_rel)

        png_rid = png_rel.attrib["Id"]
        png_target = png_rel.attrib.get("Target", "")
        for blip in doc_root.findall(f".//{{{a_ns}}}blip"):
            if blip.attrib.get(f"{{{r_ns}}}embed") != png_rid:
                continue
            ext_lst = blip.find(f"{{{a_ns}}}extLst")
            if ext_lst is None:
                ext_lst = ET.SubElement(blip, f"{{{a_ns}}}extLst")
            ext = ET.SubElement(ext_lst, f"{{{a_ns}}}ext")
            ext.attrib["uri"] = svg_ext_uri
            svg_blip = ET.SubElement(ext, f"{{{asvg_ns}}}svgBlip")
            svg_blip.attrib[f"{{{r_ns}}}embed"] = svg_rid

        existing_overrides = {
            override.attrib.get("PartName")
            for override in content_root.findall(f"{{{ct_ns}}}Override")
        }
        part_name = f"/word/{svg_target}"
        if part_name not in existing_overrides:
            override = ET.Element(f"{{{ct_ns}}}Override")
            override.attrib["PartName"] = part_name
            override.attrib["ContentType"] = "image/svg+xml"
            content_root.append(override)

        ET.register_namespace("", rel_ns)
        ET.register_namespace("a", a_ns)
        ET.register_namespace("asvg", asvg_ns)
        ET.register_namespace("r", r_ns)
        ET.register_namespace("", ct_ns)
        written: set[str] = set()
        with zipfile.ZipFile(tmp, "w", zipfile.ZIP_DEFLATED) as zout:
            for item in zin.infolist():
                if item.filename == "word/_rels/document.xml.rels":
                    zout.writestr(item, ET.tostring(rel_root, encoding="utf-8", xml_declaration=True))
                elif item.filename == "word/document.xml":
                    zout.writestr(item, ET.tostring(doc_root, encoding="utf-8", xml_declaration=True))
                elif item.filename == "[Content_Types].xml":
                    zout.writestr(item, ET.tostring(content_root, encoding="utf-8", xml_declaration=True))
                else:
                    zout.writestr(item, zin.read(item.filename))
                written.add(item.filename)
            svg_media_name = f"word/{svg_target}"
            if svg_media_name not in written:
                zout.writestr(svg_media_name, svg_path.read_bytes())
    shutil.move(str(tmp), str(docx_path))
    return {
        "docx_svg_rid": svg_rid,
        "docx_svg_media_target": svg_target,
        "docx_fallback_rid": png_rid,
        "docx_fallback_media_target": png_target,
    }


