def case_gate_source_preserved_front_matter_image_valid(td: Path) -> tuple[int, str]:
    from docx import Document  # type: ignore

    png = make_png(td / "gate-front-matter-preserved.png", 200, 120)
    final_docx = make_toc_metric_docx(td / "gate-front-matter-preserved.docx")
    doc = Document(str(final_docx))
    doc.add_picture(str(png))
    picture_paragraph = doc.paragraphs[-1]._element
    body = doc._body._element
    body.remove(picture_paragraph)
    body.insert(1, picture_paragraph)
    doc.save(str(final_docx))
    rendered_pdf = make_pdf_with_text(td / "gate-front-matter-preserved.pdf", "front matter image gate fixture")
    page_image = make_png(td / "gate-front-matter-preserved-page.png", 320, 180)
    thesis_ev = td / "gate-front-matter-preserved.thesis.md"
    paragraph_ev = td / "gate-front-matter-preserved.paragraph.md"
    touched_ev = td / "gate-front-matter-preserved.touched.md"
    figure_ev = td / "gate-front-matter-preserved.figure.md"
    common_evidence = {
        "task_mode": "thesis-only",
        "reviewed_output": final_docx,
        "artifact_paths": [rendered_pdf, page_image],
        "baseline_source_path_and_sha256": f"{final_docx} sha256={file_sha256(final_docx)}",
    }
    make_review_evidence(
        thesis_ev,
        evidence_type="thesis-rendered-page",
        target_surface="thesis page",
        target_identifier="front-matter-image",
        target_region="front matter",
        blast_radius="front matter",
        neighbors="body opener",
        checks="source-preserved front matter drawing",
        summary="front matter image preserved from source",
        **common_evidence,
    )
    make_review_evidence(
        paragraph_ev,
        evidence_type="paragraph-review",
        target_surface="paragraph",
        target_identifier="front-matter-image",
        target_region="front matter",
        blast_radius="front matter",
        neighbors="body opener",
        checks="source-preserved front matter drawing",
        summary="front matter image paragraph reviewed",
        **common_evidence,
    )
    make_review_evidence(
        touched_ev,
        evidence_type="touched-page-review",
        target_surface="touched page",
        target_identifier="front-matter-image",
        target_region="front matter",
        blast_radius="front matter",
        neighbors="body opener",
        checks="source-preserved front matter drawing",
        summary="front matter image page reviewed",
        **common_evidence,
    )
    make_review_evidence(
        figure_ev,
        evidence_type="figure-review",
        target_surface="front matter image",
        target_identifier="front-matter-image",
        target_region="front matter",
        blast_radius="front matter",
        neighbors="body opener",
        checks="source-preserved front matter drawing",
        summary="front matter image source preservation reviewed",
        **common_evidence,
    )
    citation_audit = td / "gate-front-matter-preserved.citation.md"
    make_dummy_citation_audit_report(citation_audit, passed=True, document_path=final_docx)
    format_task = td / "gate-front-matter-preserved.format-task.md"
    make_format_repair_task(
        format_task,
        review_copy=final_docx,
        thesis_paths=[thesis_ev],
        paragraph_paths=[paragraph_ev],
        touched_paths=[touched_ev],
        citation_audit_path=citation_audit,
        rendered_pdf=rendered_pdf,
        page_images=[page_image],
        touched_blocks="source-preserved image",
        format_classes="image preservation",
        sentinels="image holder",
        pages_to_inspect="page 1",
    )
    record = td / "gate-front-matter-preserved.acceptance.md"
    make_gate_record(
        record,
        task_mode="thesis-only",
        subtask="source preserved front matter image",
        output_path=final_docx,
        format_task_path=str(format_task),
        rendered_pdf=str(rendered_pdf),
        page_images=str(page_image),
        citation_audit_path=str(citation_audit),
        thesis_paths=str(thesis_ev),
        figure_paths=str(figure_ev),
        paragraph_paths=str(paragraph_ev),
        touched_page_paths=str(touched_ev),
        renderer_path=str(PYTHON_EXE),
        rasterizer_path=str(PYTHON_EXE),
        review_copy_path=str(final_docx),
        humanizer_route_decision="humanizer-zh",
        humanizer_target_language="zh",
        humanizer_scope="chinese body rewrite",
        humanizer_evidence_path="AUTO",
    )
    source_docx = record.with_suffix(".source.docx")
    manifest = add_docx_binding_fields(
        {
            "schema": "graduation-project-builder.figure-manifest.v2",
            "figures": {},
            "diagrams": {},
        },
        source_docx=source_docx,
        final_docx=final_docx,
    )
    manifest_path = td / "gate-front-matter-preserved.figure-manifest.json"
    write_text(manifest_path, json.dumps(manifest, ensure_ascii=False, indent=2) + "\n")
    replace_record_prefixes(
        record,
        {
            "- figure asset manifest path:": str(manifest_path),
            "- figure manifest contract verdict:": "pass",
            "- figure family style summary:": "passed source-preserved front-matter image",
            "- figure source/style contract summary:": "passed source-preserved front-matter image",
        },
    )
    proc = run_validator(record)
    return proc.returncode, proc.stdout


