def case_docx_sync_picture_svg_replace_preserves_comment_anchors_valid(td: Path) -> tuple[int, str]:
    from xml.etree import ElementTree as ET

    from docx_sync_picture import patch_docx
    from thesis_figure_contract import validate_figure_manifest

    w_ns = "http://schemas.openxmlformats.org/wordprocessingml/2006/main"
    source_png = make_png(td / "comment-anchor-source.png", 1200, 1600)
    replacement_png = make_png(td / "comment-anchor-replacement.png", 1200, 800, fill="#f8fafc")
    replacement_svg = write_svg(td / "comment-anchor-replacement.svg")
    replacement_drawio = make_valid_flowchart_drawio(td / "comment-anchor-replacement.drawio")
    caption = "\u56fe3-1  \u6279\u6ce8\u951a\u70b9\u4fdd\u7559\u56fe"
    source_docx = make_vml_picture_docx(td / "comment-anchor-source.docx", source_png, caption=caption, width="4cm")

    with zipfile.ZipFile(source_docx, "r") as zin:
        members = {item.filename: zin.read(item.filename) for item in zin.infolist()}
    root = ET.fromstring(members["word/document.xml"])
    picture_para = next(
        para
        for para in root.findall(".//{%s}p" % w_ns)
        if para.find(".//{%s}drawing" % w_ns) is not None or para.find(".//{%s}pict" % w_ns) is not None
    )
    start = ET.Element("{%s}commentRangeStart" % w_ns)
    start.set("{%s}id" % w_ns, "5")
    end = ET.Element("{%s}commentRangeEnd" % w_ns)
    end.set("{%s}id" % w_ns, "5")
    ref_run = ET.Element("{%s}r" % w_ns)
    ref = ET.SubElement(ref_run, "{%s}commentReference" % w_ns)
    ref.set("{%s}id" % w_ns, "5")
    insert_at = 1 if list(picture_para) and list(picture_para)[0].tag == "{%s}pPr" % w_ns else 0
    picture_para.insert(insert_at, start)
    picture_para.append(end)
    picture_para.append(ref_run)
    members["word/document.xml"] = ET.tostring(root, encoding="utf-8", xml_declaration=True)
    comments_xml = (
        '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
        '<w:comments xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">'
        '<w:comment w:id="5" w:author="teacher"><w:p><w:r><w:t>resize figure</w:t></w:r></w:p></w:comment>'
        "</w:comments>"
    )
    members["word/comments.xml"] = comments_xml.encode("utf-8")
    with zipfile.ZipFile(source_docx, "w", zipfile.ZIP_DEFLATED) as zout:
        for name, payload in members.items():
            zout.writestr(name, payload)

    evidence = figure_manifest_common_evidence(td, "svg-primary", caption, replacement_png)
    entry = {
        "caption": caption,
        "family": "flowchart",
        "declared_family": "flowchart",
        "inferred_family": "flowchart",
        "source_kind": "drawio",
        "final_source_kind": "drawio",
        "authoring_tool": "draw.io",
        "path": str(replacement_png),
        "png": str(replacement_png),
        "svg": str(replacement_svg),
        "drawio": str(replacement_drawio),
        **evidence,
    }
    manifest = {
        "schema": "graduation-project-builder.figure-manifest.v2",
        "figures": {"figure_3_1": dict(entry)},
        "diagrams": {"figure_3_1": dict(entry)},
        "tables": {},
    }
    manifest_path = td / "comment-anchor-manifest.json"
    write_text(manifest_path, json.dumps(manifest, ensure_ascii=False, indent=2) + "\n")
    final_docx = td / "comment-anchor-final.docx"
    patch_docx(
        docx_path=source_docx,
        para_id=None,
        image_path=replacement_png,
        svg_image_path=replacement_svg,
        new_label="comment anchor preserving figure",
        output_path=final_docx,
        caption=caption,
        manifest_path=manifest_path,
        source_docx=source_docx,
        mode="replace",
        resize_width_cm=8.0,
    )
    final_manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
    issues = validate_figure_manifest(
        final_manifest,
        source_docx=source_docx,
        final_docx=final_docx,
        manifest_path=manifest_path,
    )
    with zipfile.ZipFile(final_docx) as zf:
        final_root = ET.fromstring(zf.read("word/document.xml"))
    final_picture_para = next(
        para
        for para in final_root.findall(".//{%s}p" % w_ns)
        if para.find(".//{%s}drawing" % w_ns) is not None or para.find(".//{%s}pict" % w_ns) is not None
    )
    anchor_tags = [
        child.tag.rsplit("}", 1)[-1] + ":" + child.attrib.get("{%s}id" % w_ns, "")
        for child in final_picture_para.iter()
        if child.tag
        in {
            "{%s}commentRangeStart" % w_ns,
            "{%s}commentRangeEnd" % w_ns,
            "{%s}commentReference" % w_ns,
        }
    ]
    expected = {"commentRangeStart:5", "commentRangeEnd:5", "commentReference:5"}
    ok = not issues and expected.issubset(set(anchor_tags))
    return (0 if ok else 1, "\n".join(issues) or json.dumps(anchor_tags, ensure_ascii=False))


