def case_figure_manifest_narrative_figure_reference_not_caption_valid(td: Path) -> tuple[int, str]:
    from thesis_figure_contract import docx_figure_surface_summary, is_docx_figure_caption

    png = td / "runtime.png"
    make_png(png, 1200, 800)
    final_docx = make_body_picture_docx(
        td / "figure-reference-not-caption.docx",
        png,
        caption="\u56fe3-1  \u57fa\u4e8e YOLOv8-Pose \u7684\u5f02\u5e38\u884c\u4e3a\u68c0\u6d4b\u5904\u7406\u94fe\u8def\u56fe",
    )
    # Insert a normal explanatory paragraph before the image. It references the
    # figure but is not the official caption because no separator follows the number.
    with zipfile.ZipFile(final_docx, "r") as zin:
        document_xml = zin.read("word/document.xml").decode("utf-8")
    marker = "<w:p><w:r><w:drawing>"
    narrative = (
        "<w:p><w:r><w:t>"
        "\u56fe3-1\u5c55\u793a\u4e86\u672c\u7814\u7a76\u7684\u5904\u7406\u94fe\u8def\u3002"
        "</w:t></w:r></w:p>"
    )
    document_xml = document_xml.replace(marker, narrative + marker, 1)
    tmp = final_docx.with_suffix(".tmp.docx")
    with zipfile.ZipFile(final_docx, "r") as zin, zipfile.ZipFile(tmp, "w", zipfile.ZIP_DEFLATED) as zout:
        for item in zin.infolist():
            payload = document_xml.encode("utf-8") if item.filename == "word/document.xml" else zin.read(item.filename)
            zout.writestr(item, payload)
    shutil.move(str(tmp), str(final_docx))

    summary = docx_figure_surface_summary(final_docx)
    narrative_is_caption = is_docx_figure_caption("\u56fe3-1\u5c55\u793a\u4e86\u672c\u7814\u7a76\u7684\u5904\u7406\u94fe\u8def\u3002")
    ok = (
        not narrative_is_caption
        and summary["figure_caption_count"] == 1
        and summary["body_drawing_block_count"] == 1
        and summary["orphan_caption_count"] == 0
    )
    return (0 if ok else 1, json.dumps(summary, ensure_ascii=False, indent=2))


