def case_figure_manifest_required_er_valid(td: Path) -> tuple[int, str]:
    from docx import Document  # type: ignore
    from docx.shared import Inches  # type: ignore
    from thesis_figure_contract import build_figure_asset_manifest, drawio_er_geometry_report, validate_figure_manifest

    png = make_png(td / "er-valid-required.png", 1200, 800)
    drawio = make_er_drawio(td / "er-valid-required.drawio", overlap=False)
    svg = write_svg(td / "er-valid-required.svg")
    report_path = td / "er-valid-required.geometry.json"
    report_path.write_text(json.dumps(drawio_er_geometry_report(drawio), ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    task_card = td / "er-task-card.md"
    task_card.write_text("- final verdict: pass\n", encoding="utf-8")
    final_docx = td / "final-db-design-with-er.docx"
    doc = Document()
    doc.add_paragraph("4 数据库设计")
    doc.add_paragraph("4.1 数据库概念设计")
    doc.add_paragraph("在线学习资源共享平台的主要实体包括用户实体、资源实体、分类实体和收藏实体。")
    doc.add_picture(str(png), width=Inches(5.0))
    doc.add_paragraph("图4-2 数据库ER图")
    doc.save(final_docx)
    docx_svg_pair = add_svg_primary_fallback_to_docx(final_docx, svg)
    source_docx = td / "source-db-design-with-er.docx"
    shutil.copyfile(final_docx, source_docx)
    manifest = build_figure_asset_manifest(
        figure_content(
            {
                "family": "er",
                "caption": "图4-2 数据库ER图",
                "image_path": str(png),
                "drawio_path": str(drawio),
                "svg_path": str(svg),
                "geometry_validation_report": str(report_path),
                "source_scale_bbox_map": str(report_path),
                "inserted_scale_geometry_evidence": str(report_path),
                "dense_zone_crop_evidence": str(report_path),
                **figure_manifest_common_evidence(td, "er-valid-required", "图4-2 数据库ER图", png),
                "collision_check_verdict": "pass",
                "relation_attribute_collision_verdict": "pass",
                "shape_overlap_verdict": "pass",
                "inserted_scale_collision_verdict": "pass",
                "source_to_inserted_geometry_verdict": "pass",
            }
        ),
        td,
    )
    for bucket_name in ("figures", "diagrams"):
        for entry in (manifest.get(bucket_name) or {}).values():
            if isinstance(entry, dict):
                entry.update(docx_svg_pair)
                entry["svg_primary_png_fallback_verdict"] = "pass"
    manifest["required_figures"] = {
        "database_er_diagram": {
            "id": "database_er_diagram",
            "family": "er",
            "caption": "图4-2 数据库ER图",
            "status": "pass",
            "task_card": str(task_card),
            "post_insertion_rendered_evidence": str(png),
            "final_docx_relationship_evidence": str(report_path),
        }
    }
    manifest["source_docx_path"] = str(source_docx)
    manifest["source_docx_sha256"] = file_sha256(source_docx)
    manifest["final_docx_path"] = str(final_docx)
    manifest["final_docx_sha256"] = file_sha256(final_docx)
    issues = validate_figure_manifest(manifest, source_docx=source_docx, final_docx=final_docx)
    return (0 if not issues else 1, "\n".join(issues))


