def run_sample_self_check_delivery_fixture(td: Path, *, smoke_acceptance: bool) -> tuple[int, str]:
    fixture = make_sample_self_check_delivery_fixture(td / ("sample-self-check-smoke" if smoke_acceptance else "sample-self-check-default"))
    output = td / ("sample-self-check-smoke.md" if smoke_acceptance else "sample-self-check-default.md")
    cmd = [
        str(PYTHON_EXE),
        str(SKILL_ROOT / "scripts" / "sample_self_check.py"),
        "--reference-docx",
        str(fixture["reference_docx"]),
        "--final-docx",
        str(fixture["final_docx"]),
        "--final-pdf",
        str(fixture["final_pdf"]),
        "--citation-audit",
        str(fixture["citation_audit"]),
        "--font-audit",
        str(fixture["font_audit"]),
        "--body-style-audit",
        str(fixture["body_style_audit"]),
        "--output",
        str(output),
    ]
    if smoke_acceptance:
        cmd.append("--smoke-acceptance")
    proc = subprocess.run(
        cmd,
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(MEDIUM_SUBPROCESS_TIMEOUT),
    )
    report = output.read_text(encoding="utf-8", errors="replace") if output.exists() else ""
    return proc.returncode, (proc.stdout or "") + (proc.stderr or "") + "\n" + report


