def case_sample_self_check_common_submission_rejected(td: Path) -> tuple[int, str]:
    docx_path = make_raw_docx(
        td / "common-submission-bad.docx",
        """
    <w:p><w:r><w:t>目录</w:t></w:r></w:p>
    <w:p><w:r><w:t>1 绪论 1</w:t></w:r></w:p>
    <w:p><w:r><w:t>1 绪论</w:t></w:r></w:p>
    <w:p><w:r><w:t>正文内容[1]</w:t></w:r></w:p>
    <w:p><w:r><w:t>参考文献</w:t></w:r></w:p>
    <w:p><w:r><w:t>[1] 测试文献.</w:t></w:r></w:p>
""",
    )
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            "-c",
            (
                "import sys; "
                f"sys.path.insert(0, {str(SKILL_ROOT / 'scripts')!r}); "
                "from pathlib import Path; "
                "from sample_self_check import extract_common_pre_submission_checks; "
                f"issues, summary, evidence = extract_common_pre_submission_checks(Path({str(docx_path)!r})); "
                "print(summary); print(evidence); print('\\n'.join(issues))"
            ),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=False,
        timeout=timeout_seconds(120),
    )
    ok = (
        proc.returncode == 0
        and "failed" in proc.stdout
        and "bibliography entry count" in proc.stdout
        and "总结与展望" in proc.stdout
    )
    return (0 if ok else 1, "common pre-submission checklist rejected incomplete thesis" if ok else proc.stdout + proc.stderr)


