def case_citation_anchor_leak_rejected(td: Path) -> tuple[int, str]:
    review_copy, rendered_pdf, page_images, thesis_ev, _para_ev, touched_ev, figure_ev, citation_audit = build_thesis_bundle(td, "thesis-only")
    bad_para = td / "citation_leak.md"
    make_review_evidence(
        bad_para,
        evidence_type="paragraph-review",
        task_mode="thesis-only",
        reviewed_output=review_copy,
        artifact_paths=[rendered_pdf, *page_images],
        target_surface="citation paragraph",
        target_identifier="cite-ref-leak",
        target_region="body paragraph with citation",
        blast_radius="page 1",
        neighbors="adjacent citation paragraph",
        checks="paragraph review",
        summary="Rendered body paragraph still shows internal anchor text cite_ref_1 next to the citation marker.",
    )
    format_task = td / "citation_leak_task.md"
    make_format_repair_task(
        format_task,
        review_copy=review_copy,
        thesis_paths=[thesis_ev],
        paragraph_paths=[bad_para],
        touched_paths=[touched_ev],
        citation_audit_path=citation_audit,
        rendered_pdf=rendered_pdf,
        page_images=page_images,
        touched_blocks="citation repair",
        format_classes="citation formatting",
        sentinels="body citation paragraph",
        pages_to_inspect="1-2",
    )
    record = td / "citation_leak.acceptance.md"
    make_gate_record(
        record,
        task_mode="thesis-only",
        subtask="citation anchor leak",
        output_path=review_copy,
        format_task_path=str(format_task),
        rendered_pdf=str(rendered_pdf),
        page_images="; ".join(str(p) for p in page_images),
        citation_audit_path=str(citation_audit),
        thesis_paths=str(thesis_ev),
        figure_paths=str(figure_ev),
        paragraph_paths=str(bad_para),
        touched_page_paths=str(touched_ev),
        renderer_path=str(PYTHON_EXE),
        rasterizer_path=str(PYTHON_EXE),
        review_copy_path=str(review_copy),
    )
    proc = run_validator(record)
    return proc.returncode, proc.stdout


