def case_body_direct_heading_like_format_audit_rejected(td: Path) -> tuple[int, str]:
    reference_docx = make_body_instance_drift_docx(td / "body_direct_reference.docx", keep_instance_metrics=True)
    final_docx = make_body_instance_drift_docx(td / "body_direct_final.docx", keep_instance_metrics=True)
    with zipfile.ZipFile(final_docx, "r") as zin:
        members = {name: zin.read(name) for name in zin.namelist()}
    document_xml = members["word/document.xml"].decode("utf-8")
    document_xml = document_xml.replace(
        "<w:r><w:t>Body paragraph two.</w:t></w:r>",
        '<w:r><w:rPr><w:b/><w:sz w:val="28"/></w:rPr><w:t>Body paragraph two.</w:t></w:r>',
        1,
    )
    members["word/document.xml"] = document_xml.encode("utf-8")
    with zipfile.ZipFile(final_docx, "w", zipfile.ZIP_DEFLATED) as zout:
        for name, data in members.items():
            zout.writestr(name, data)
    report = td / "body_direct_audit.md"
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "audit_docx_body_style.py"),
            "--reference-docx",
            str(reference_docx),
            "--final-docx",
            str(final_docx),
            "--report",
            str(report),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=False,
        timeout=timeout_seconds(120),
    )
    report_text = report.read_text(encoding="utf-8", errors="replace") if report.exists() else ""
    return proc.returncode, (proc.stdout or "") + report_text


def case_body_style_audit_acknowledgement_title_excluded_valid(td: Path) -> tuple[int, str]:
    def insert_acknowledgement_title(docx_path: Path) -> None:
        with zipfile.ZipFile(docx_path, "r") as zin:
            members = {name: zin.read(name) for name in zin.namelist()}
        document_xml = members["word/document.xml"].decode("utf-8")
        ack_xml = (
            '<w:p><w:pPr><w:pStyle w:val="Normal"/><w:jc w:val="center"/>'
            '<w:spacing w:before="312" w:after="312"/></w:pPr>'
            '<w:r><w:t>\u8c22 \u8f9e</w:t></w:r></w:p>'
        )
        document_xml = document_xml.replace(
            '<w:p><w:pPr><w:pStyle w:val="Heading1"/></w:pPr><w:r><w:t>References</w:t></w:r></w:p>',
            ack_xml + '\n    <w:p><w:pPr><w:pStyle w:val="Heading1"/></w:pPr><w:r><w:t>References</w:t></w:r></w:p>',
        )
        members["word/document.xml"] = document_xml.encode("utf-8")
        with zipfile.ZipFile(docx_path, "w", zipfile.ZIP_DEFLATED) as zout:
            for name, data in members.items():
                zout.writestr(name, data)

    reference_docx = make_body_instance_drift_docx(td / "body_ack_reference.docx", keep_instance_metrics=True)
    final_docx = make_body_instance_drift_docx(td / "body_ack_final.docx", keep_instance_metrics=True)
    insert_acknowledgement_title(reference_docx)
    insert_acknowledgement_title(final_docx)
    report = td / "body_ack_audit.md"
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "audit_docx_body_style.py"),
            "--reference-docx",
            str(reference_docx),
            "--final-docx",
            str(final_docx),
            "--report",
            str(report),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=False,
        timeout=timeout_seconds(120),
    )
    report_text = report.read_text(encoding="utf-8", errors="replace") if report.exists() else ""
    return proc.returncode, (proc.stdout or "") + report_text


