def run_transaction_validator(record: Path, final_docx: Path) -> subprocess.CompletedProcess[str]:
    return subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "validate_thesis_mutation_transaction.py"),
            "--record",
            str(record),
            "--final-docx",
            str(final_docx),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )


def run_comment_resolution_audit(
    final_docx: Path,
    *,
    source_docx: Path | None = None,
    ledger: Path | None = None,
    assert_all_resolved: bool = False,
) -> subprocess.CompletedProcess[str]:
    cmd = [
        str(PYTHON_EXE),
        str(SKILL_ROOT / "scripts" / "audit_thesis_comment_resolution.py"),
        "--final-docx",
        str(final_docx),
    ]
    if source_docx is not None:
        cmd.extend(["--source-docx", str(source_docx)])
    if ledger is not None:
        cmd.extend(["--ledger", str(ledger)])
    if assert_all_resolved:
        cmd.append("--assert-all-resolved")
    return subprocess.run(
        cmd,
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )


