def case_picture_sync_helper_valid(td: Path) -> tuple[int, str]:
    original_png = make_png_file(td / "orig.png")
    replacement_png = make_png_file(td / "replacement.png")
    docx_path = td / "picture_sync.docx"
    para_id = make_picture_docx(docx_path, original_png, caption="Figure 1 Original")
    source_docx = td / "picture_sync.source.docx"
    shutil.copyfile(docx_path, source_docx)
    manifest_path = td / "picture_sync.figure-manifest.json"
    manifest = {
        "schema": "graduation-project-builder.figure-manifest.v2",
        "figures": {
            "figure_1": {
                "family": "raster",
                "source_kind": "raster",
                "caption": "Figure 1 Original",
                "path": str(replacement_png),
                **figure_manifest_common_evidence(td, "picture-sync", "Figure 1 Original", replacement_png),
            }
        },
        "tables": {},
        "diagrams": {},
    }
    write_text(manifest_path, json.dumps(manifest, ensure_ascii=False, indent=2) + "\n")
    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "docx_sync_picture.py"),
            "--docx",
            str(docx_path),
            "--para-id",
            para_id,
            "--image",
            str(replacement_png),
            "--label",
            "Figure 1 Replacement",
            "--figure-manifest",
            str(manifest_path),
            "--source-docx",
            str(source_docx),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=False,
        timeout=timeout_seconds(120),
    )
    if proc.returncode != 0:
        return proc.returncode, proc.stdout + proc.stderr
    with zipfile.ZipFile(docx_path) as zf:
        doc_xml = zf.read("word/document.xml").decode("utf-8", errors="replace")
        rels_xml = zf.read("word/_rels/document.xml.rels").decode("utf-8", errors="replace")
    manifest_after = json.loads(manifest_path.read_text(encoding="utf-8"))
    entry_after = next(iter(manifest_after["figures"].values()))
    ok = (
        "Figure 1 Replacement" in doc_xml
        and entry_after.get("final_rid") == entry_after.get("original_rid")
        and entry_after.get("final_media_target") == entry_after.get("original_media_target")
        and entry_after.get("final_media_sha256") == file_sha256(replacement_png)
    )
    return (0 if ok else 1, proc.stdout + doc_xml + rels_xml)


