def case_citation_chain_normalizer_valid(td: Path) -> tuple[int, str]:
    docx_path = make_raw_citation_docx(td / "citation_chain.docx")
    normalize_proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "normalize_thesis_citation_chain.py"),
            "--docx",
            str(docx_path),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=False,
        timeout=timeout_seconds(120),
    )
    if normalize_proc.returncode != 0:
        return normalize_proc.returncode, normalize_proc.stdout + normalize_proc.stderr
    audit_proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(CITATION_AUDIT_SCRIPT),
            "--docx",
            str(docx_path),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=False,
        timeout=timeout_seconds(120),
    )
    output = (normalize_proc.stdout or "") + (audit_proc.stdout or "") + (audit_proc.stderr or "")
    if audit_proc.returncode != 0:
        return audit_proc.returncode, output
    with zipfile.ZipFile(docx_path) as zf:
        doc_xml = zf.read("word/document.xml").decode("utf-8", errors="replace")
    preservation_ok = (
        "<w:b" in doc_xml
        and "<w:i" in doc_xml
        and "cite_ref_1" in doc_xml
        and "<w:t>[1]</w:t>" in doc_xml
        and "<w:t> Five[J].</w:t>" in doc_xml
    )
    if not preservation_ok:
        return 1, output + "\nBibliography run preservation check failed.\n" + doc_xml
    return 0, output


