def case_heading_collector_bilingual_valid_v2(td: Path) -> tuple[int, str]:
    docx_path = td / "heading_collector.docx"
    output_json = td / "heading_pages.json"
    create_proc = subprocess.run(
        [
            str(PYTHON_EXE),
            "-c",
            (
                "from docx import Document; "
                f"doc=Document(); "
                "doc.add_paragraph('Contents', style='TOC Heading'); "
                "doc.add_paragraph('1 Introduction', style='Heading 1'); "
                "doc.add_paragraph('1.1 Background', style='Heading 2'); "
                "doc.add_paragraph('1.1.1 Scope', style='Heading 3'); "
                f"doc.save(r'{docx_path}')"
            ),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=False,
        timeout=timeout_seconds(120),
    )
    if create_proc.returncode != 0:
        return create_proc.returncode, create_proc.stdout + create_proc.stderr

    proc = subprocess.run(
        [
            str(PYTHON_EXE),
            str(SKILL_ROOT / "scripts" / "collect_heading_pages_word.py"),
            "--input",
            str(docx_path),
            "--output",
            str(output_json),
        ],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        check=False,
        timeout=timeout_seconds(180),
    )
    if proc.returncode != 0:
        return proc.returncode, proc.stdout + proc.stderr
    rows = json.loads(output_json.read_text(encoding="utf-8"))
    levels = [row["level"] for row in rows]
    ok = levels == [1, 2, 3]
    return (0 if ok else 1, proc.stdout + json.dumps(rows, ensure_ascii=False))


def case_heading_collector_fullwidth_dot_and_tail_valid(td: Path) -> tuple[int, str]:
    import importlib.util

    from docx import Document  # type: ignore

    docx_path = td / "heading_collector_fullwidth.docx"
    doc = Document()
    doc.add_paragraph("目    录")
    doc.add_paragraph("摘要I")
    doc.add_paragraph("1  引言")
    doc.add_paragraph("1．1  研究背景")
    doc.add_paragraph("1．1．1  研究范围")
    references_title = doc.add_paragraph("参考文献")
    set_visible_metrics(references_title)
    acknowledgement_title = doc.add_paragraph("致谢")
    set_visible_metrics(acknowledgement_title)
    doc.save(docx_path)

    script_path = SKILL_ROOT / "scripts" / "collect_heading_pages_word.py"
    spec = importlib.util.spec_from_file_location("collect_heading_pages_word", script_path)
    if spec is None or spec.loader is None:
        return 1, f"cannot load {script_path}"
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    rows = module.collect_docx_heading_rows(docx_path)
    levels = [row["level"] for row in rows]
    texts = [row["text"] for row in rows]
    ok = levels == [1, 2, 3, 1, 1] and texts == [
        "1  引言",
        "1．1  研究背景",
        "1．1．1  研究范围",
        "参考文献",
        "致谢",
    ]
    return (0 if ok else 1, json.dumps(rows, ensure_ascii=False))


