def case_integration_gate_inventory_parity_valid(td: Path) -> tuple[int, str]:
    script = textwrap.dedent(
        f"""
        import importlib
        import json
        import sys
        from pathlib import Path

        path = Path(r"{INTEGRATION_GATE}")
        sys.path.insert(0, str(path.parent))
        module = importlib.import_module("run_integration_gate")
        actual = list(module.CASE_SEQUENCE)
        expected = {json.dumps(EXPECTED_INTEGRATION_CASES, ensure_ascii=False)}
        if actual != expected:
            print("INVENTORY PARITY FAIL")
            print("ACTUAL=" + json.dumps(actual, ensure_ascii=False))
            print("EXPECTED=" + json.dumps(expected, ensure_ascii=False))
            raise SystemExit(1)
        print("INVENTORY PARITY PASS")
        """
    )
    proc = subprocess.run(
        [str(PYTHON_EXE), "-c", script],
        capture_output=True,
        text=True,
        encoding="utf-8",
        errors="replace",
        timeout=timeout_seconds(SHORT_SUBPROCESS_TIMEOUT),
    )
    return proc.returncode, (proc.stdout or "") + (proc.stderr or "")


def case_integration_gate_diagnostic_pdf_fallback_retired_valid(td: Path) -> tuple[int, str]:
    import importlib

    module = importlib.import_module("run_integration_gate")
    reference = make_minimal_review_docx(td / "reference.docx")
    final = make_minimal_review_docx(td / "final.docx")
    fixture_root = td / "diagnostic_pdf_fallback_retired"
    env = module.GateEnvironment(
        officecli="not-found",
        renderer="unavailable",
        libreoffice="not-found",
        wps="not-found",
    )
    original_export = module.export_pdf_with_sample_fallback
    original_diagnostic = module.create_diagnostic_pdf_from_docx
    diagnostic_called = False

    def fail_export(*_args, **_kwargs):
        raise RuntimeError("forced renderer failure")

    def fail_diagnostic(*_args, **_kwargs):
        nonlocal diagnostic_called
        diagnostic_called = True
        raise AssertionError("diagnostic PDF fallback called")

    module.export_pdf_with_sample_fallback = fail_export
    module.create_diagnostic_pdf_from_docx = fail_diagnostic
    try:
        try:
            module.run_sample_self_check_suite(
                reference,
                final,
                fixture_root,
                "forced-renderer-failure",
                env=env,
                smoke_acceptance=True,
            )
        except module.GateFailure as exc:
            output = str(exc)
            ok = (
                "diagnostic PDF fallback is not acceptable" in output
                and not diagnostic_called
                and not (fixture_root / "forced-renderer-failure.pdf").exists()
            )
            return (0 if ok else 1, output)
        except AssertionError as exc:
            return 1, str(exc)
        return 1, "renderer failure unexpectedly reached sample self-check without GateFailure"
    finally:
        module.export_pdf_with_sample_fallback = original_export
        module.create_diagnostic_pdf_from_docx = original_diagnostic


