FAST_CASE_NAMES = FAST_CORE_CASE_NAMES | FAST_THESIS_RECORD_CASE_NAMES
ALL_DEFAULT_CASE_NAMES = FAST_CORE_CASE_NAMES | FAST_THESIS_RECORD_CASE_NAMES


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument(
        "--suite",
        choices=["fast", "fast-core", "fast-thesis-records", "integration", "all"],
        default="fast",
        help="Select the selftest layer. fast is bounded; integration runs the canonical integration gate once plus inventory parity.",
    )
    parser.add_argument(
        "--include-integration",
        action="store_true",
        help="Compatibility alias for --suite all.",
    )
    parser.add_argument(
        "--case",
        action="append",
        dest="case_names",
        help="Run only the named selftest case. Repeat the flag for multiple cases.",
    )
    parser.add_argument("--quiet", action="store_true", help="Print only summary and failing case details.")
    parser.add_argument("--report-out", help="Write a machine-readable JSON report for all case output.")
    parser.add_argument("--fail-fast", action="store_true", help="Stop after the first failing case.")
    parser.add_argument("--list-cases", action="store_true", help="List selected case names and exit.")
    parser.add_argument(
        "--no-timeouts",
        action="store_true",
        help="Disable internal subprocess timeouts for long-running full skill validation runs.",
    )
    args = parser.parse_args()
    global DISABLE_SUBPROCESS_TIMEOUTS
    if args.no_timeouts:
        DISABLE_SUBPROCESS_TIMEOUTS = True

    suite = "all" if args.include_integration else args.suite
    all_cases = list(CASES) + list(INTEGRATION_CASES)
    if args.case_names:
        cases = all_cases
    elif suite == "fast-core":
        cases = [case for case in CASES if case[0] in FAST_CORE_CASE_NAMES]
    elif suite == "fast-thesis-records":
        cases = [case for case in CASES if case[0] in FAST_THESIS_RECORD_CASE_NAMES]
    elif suite == "fast":
        cases = [case for case in CASES if case[0] in FAST_CASE_NAMES]
    elif suite == "integration":
        cases = [case for case in INTEGRATION_CASES if case[0] in DEFAULT_INTEGRATION_CASE_NAMES]
    else:
        cases = [case for case in CASES if case[0] in ALL_DEFAULT_CASE_NAMES]
        cases.extend(case for case in INTEGRATION_CASES if case[0] in DEFAULT_INTEGRATION_CASE_NAMES)
    if args.case_names:
        requested = set(args.case_names)
        available = {name for name, _, _, _ in cases}
        unknown = sorted(requested - available)
        if unknown:
            print(f"Unknown selftest case(s): {', '.join(unknown)}")
            return 2
        cases = [case for case in cases if case[0] in requested]
    if args.list_cases:
        for name, _builder, _expected_code, _expected_needle in cases:
            print(name)
        return 0

    all_ok = True
    results: list[dict[str, object]] = []
    for name, builder, expected_code, expected_needle in cases:
        with tempfile.TemporaryDirectory(prefix="codex_skill_flow_", ignore_cleanup_errors=True) as td_raw:
            td = Path(td_raw)
            code, out = builder(td)
            ok = code == expected_code and expected_needle in out
            first_line = out.splitlines()[0] if out else ""
            result = {
                "name": name,
                "exit": code,
                "expected_exit": expected_code,
                "ok": ok,
                "needle_found": expected_needle in out,
                "expected_needle": expected_needle,
                "first_line": first_line,
                "output": out,
            }
            results.append(result)
            if args.quiet:
                if not ok:
                    print(console_safe(f"CASE {name}: exit={code}, expected={expected_code}, ok={ok}"))
                    print(console_safe(f"  first_line={first_line}"))
                    print(f"  needle_found={expected_needle in out}")
            else:
                print(console_safe(f"CASE {name}: exit={code}, expected={expected_code}, ok={ok}"))
                print(console_safe(f"  first_line={first_line}"))
                print(f"  needle_found={expected_needle in out}")
            all_ok = all_ok and ok
            if not ok and args.fail_fast:
                break
    if args.report_out:
        report_path = Path(args.report_out).resolve()
        report_path.parent.mkdir(parents=True, exist_ok=True)
        report_path.write_text(
            json.dumps(
                {
                    "suite": suite,
                    "case_count": len(results),
                    "passed": all_ok,
                    "subprocess_timeouts_disabled": DISABLE_SUBPROCESS_TIMEOUTS,
                    "results": results,
                },
                ensure_ascii=False,
                indent=2,
            )
            + "\n",
            encoding="utf-8",
        )
    timeout_mode = "disabled" if DISABLE_SUBPROCESS_TIMEOUTS else "enabled"
    print(f"SELFTEST SUITE={suite} CASES={len(results)} TIMEOUTS={timeout_mode} OVERALL={'PASS' if all_ok else 'FAIL'}")
    return 0 if all_ok else 1


if __name__ == "__main__":
    raise SystemExit(main())
